BEGIN;

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, a ________ resistance is connected in ________ with the galvanometer.", "explanation": "To convert a galvanometer into a voltmeter, a high resistance is connected in series with it. The high series resistance ensures that the voltmeter draws negligible current from the circuit, thereby not disturbing the potential difference being measured. The total resistance of the voltmeter becomes R + G, where R >> G.", "correct_answer": "A", "concept_tags": ["voltmeter conversion", "series resistance"], "payload": {"question_id": "cuet-phy-mag-devices-35", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "high; series", "is_correct": true}, {"key": "B", "value": "low; series", "is_correct": false}, {"key": "C", "value": "high; parallel", "is_correct": false}, {"key": "D", "value": "low; parallel", "is_correct": false}], "elimination_hints": ["A voltmeter must have high resistance to avoid drawing significant current—this eliminates options with ''low'' resistance.", "A voltmeter measures potential difference across a component, so it must be connected in parallel with the component, but the internal conversion uses series connection.", "Low resistance in parallel describes an ammeter conversion (shunt), not a voltmeter conversion."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In a moving coil galvanometer, a radial magnetic field is produced by using concave-shaped pole pieces and a _____ placed inside the coil.", "explanation": "A soft iron core is placed inside the coil of a moving coil galvanometer. The soft iron core, along with the concave-shaped (cylindrical) pole pieces of the permanent magnet, creates a radial magnetic field. In a radial field, the plane of the coil is always parallel to the magnetic field direction, so the torque τ = NIAB sin(90°) = NIAB for all angular positions. This ensures a linear relationship between the current and the deflection angle (θ ∝ I).", "correct_answer": "C", "concept_tags": ["moving-coil-galvanometer", "radial-field", "soft-iron-core", "construction"], "payload": {"question_id": "cuet-phy-mag-devices-36", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Hard iron core", "is_correct": false}, {"key": "B", "text": "Copper cylinder", "is_correct": false}, {"key": "C", "text": "Soft iron core", "is_correct": true}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Hard iron retains magnetism (used for permanent magnets) and is not suitable for the core. Soft iron is used because it has high permeability, low retentivity, and strengthens the radial field without permanent magnetization.", "misconception": "Confusing soft iron (high permeability, low retentivity) with hard iron (permanent magnets)"}, {"option_key": "B", "hint": "A copper cylinder is not used as the core. Copper is non-magnetic and would not help in creating a radial magnetic field. Soft iron''s high magnetic permeability is essential for concentrating field lines.", "misconception": "Confusing copper damping mechanism with the iron core"}, {"option_key": "D", "hint": "The permanent magnet provides the external magnetic field and is located outside the coil (as pole pieces). The core inside the coil is soft iron, which helps make this external field radial.", "misconception": "Confusing the location and role of the permanent magnet with the core"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "If the student first converts the galvanometer into an ammeter of range 0–2 A and then uses the same galvanometer (after removing the shunt) to make a voltmeter of range 0–50 V, what is the difference between the high resistance needed for the voltmeter and the shunt resistance needed for the ammeter?", "explanation": "For the ammeter: S = IgG/(I − Ig) = (0.004 × 25)/(2 − 0.004) = 0.1/1.996 ≈ 0.05 Ω. For the voltmeter: R = V/Ig − G = 50/0.004 − 25 = 12,500 − 25 = 12,475 Ω. Difference = 12,475 − 0.05 = 12,474.95 ≈ 12,475 Ω. The voltmeter resistance is overwhelmingly larger than the shunt resistance.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "voltmeter conversion", "shunt resistance", "series resistance"], "payload": {"question_id": "cuet-phy-mag-devices-37", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "12,500 Ω", "is_correct": false}, {"key": "B", "value": "12,450 Ω", "is_correct": false}, {"key": "C", "value": "12,475 Ω (approx.)", "is_correct": true}, {"key": "D", "value": "12,525 Ω", "is_correct": false}], "elimination_hints": ["The shunt resistance is very small (~0.05 Ω), so the difference is approximately equal to the voltmeter''s series resistance itself.", "Voltmeter series resistance R = V/Ig − G = 12,500 − 25 = 12,475 Ω. The shunt is negligible in comparison.", "12,500 Ω would be the answer if G were zero—but we must subtract G = 25 Ω from the total."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A medical research lab uses a cyclotron to produce radioactive isotopes for PET (Positron Emission Tomography) scans. The cyclotron accelerates protons using a magnetic field of 2.0 T. The protons are extracted when they reach a radius of 0.4 m from the centre. If the cyclotron''s oscillating electric field operates at a fixed frequency, what is the frequency of the oscillating electric field, and what is the kinetic energy of the extracted protons? (Given: mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C)", "explanation": "The cyclotron frequency f = qB/(2πm) = (1.6 x 10^-19 x 2.0)/(2π x 1.67 x 10^-27) = 3.2 x 10^-19 / (1.049 x 10^-26) = 3.05 x 10^7 Hz ≈ 30.5 MHz. The maximum kinetic energy KE = q²B²R²/(2m) = (1.6 x 10^-19)² x (2.0)² x (0.4)² / (2 x 1.67 x 10^-27) = (2.56 x 10^-38 x 4 x 0.16) / (3.34 x 10^-27) = 1.638 x 10^-38 / 3.34 x 10^-27 = 4.9 x 10^-12 J. Converting: 4.9 x 10^-12 / 1.6 x 10^-13 ≈ 30.6 MeV. So the frequency is approximately 30.5 MHz and KE is approximately 30.6 MeV.", "correct_answer": "B", "concept_tags": ["cyclotron", "frequency", "kinetic-energy", "PET-scan", "medical-application", "numerical"], "payload": {"question_id": "cuet-phy-mag-devices-38", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "Frequency ≈ 15.2 MHz, KE ≈ 15 MeV", "is_correct": false}, {"key": "B", "text": "Frequency ≈ 30.5 MHz, KE ≈ 30.6 MeV", "is_correct": true}, {"key": "C", "text": "Frequency ≈ 30.5 MHz, KE ≈ 61 MeV", "is_correct": false}, {"key": "D", "text": "Frequency ≈ 61 MHz, KE ≈ 30.6 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "15.2 MHz is half the correct frequency. Check your calculation: f = qB/(2πm). With B = 2.0 T, the numerator is qB = 3.2 x 10^-19, not 1.6 x 10^-19. Ensure you use B = 2.0 T, not 1.0 T.", "misconception": "Using B = 1.0 T instead of 2.0 T in the frequency formula"}, {"option_key": "C", "hint": "The frequency is correct at 30.5 MHz, but 61 MeV is double the actual KE. Verify the factor of 2 in the denominator: KE = q²B²R²/(2m), not q²B²R²/m.", "misconception": "Forgetting the factor of 2 in the kinetic energy denominator"}, {"option_key": "D", "hint": "61 MHz is double the correct frequency. The formula is f = qB/(2πm), and 2π ≈ 6.28, not π ≈ 3.14. Using π instead of 2π would give the wrong answer.", "misconception": "Using π instead of 2π in the cyclotron frequency formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct logical sequence for converting a galvanometer into an ammeter:", "explanation": "The correct sequence is: First, determine the galvanometer parameters Ig and G (step 2). Then, identify the desired ammeter range I (step 4). Next, use these values to calculate the required shunt resistance S = IgG/(I − Ig) (step 1). Finally, physically connect the shunt in parallel with the galvanometer (step 3). This sequence follows the logical flow from characterization to design to implementation.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "shunt resistance", "logical sequence"], "payload": {"question_id": "cuet-phy-mag-devices-39", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "1, 2, 3, 4", "is_correct": false}, {"key": "B", "value": "4, 2, 1, 3", "is_correct": false}, {"key": "C", "value": "2, 4, 1, 3", "is_correct": true}, {"key": "D", "value": "2, 1, 4, 3", "is_correct": false}], "elimination_hints": ["You must know the galvanometer''s properties (Ig, G) before anything else—step 2 comes first.", "You cannot calculate the shunt (step 1) without knowing the desired range (step 4)—so step 4 must come before step 1.", "Physical connection (step 3) is always the last step—it comes after all calculations are done."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following events in the correct sequence that occurs when a current is passed through a moving coil galvanometer:", "explanation": "The correct sequence of events is: First, current flows through the coil in the radial magnetic field (step 3). This creates a deflecting torque on the coil (step 2, τ = NIAB). The coil then rotates and continues until the deflecting torque is balanced by the restoring torque of the spring (step 4, NIAB = kθ). Finally, the pointer shows the deflection on the scale (step 1). This follows the cause-and-effect chain from electrical input to mechanical output.", "correct_answer": "A", "concept_tags": ["galvanometer working", "deflecting torque", "restoring torque"], "payload": {"question_id": "cuet-phy-mag-devices-40", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "3, 2, 4, 1", "is_correct": true}, {"key": "B", "value": "2, 3, 1, 4", "is_correct": false}, {"key": "C", "value": "3, 2, 1, 4", "is_correct": false}, {"key": "D", "value": "2, 3, 4, 1", "is_correct": false}], "elimination_hints": ["The process starts with current flowing through the coil—this is the input, so step 3 comes first.", "The pointer reading (step 1) is the final output—it must come last.", "Torque (step 2) is caused by the current (step 3), and the coil must rotate and reach equilibrium (step 4) before the reading is taken (step 1)."]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electrostatic force between two point charges is a central force.\nReason (R): The force acts along the line joining the two charges and depends only on the distance between them.", "explanation": "A central force is one that acts along the line joining two particles and depends only on the scalar distance between them. Coulomb''s force F = kq₁q₂r̂/r² satisfies both conditions — it acts along r̂ (the unit vector from one charge to the other) and depends only on r. The reason correctly states both defining properties of a central force, making it the correct explanation of the assertion.", "correct_answer": "A", "concept_tags": ["central-force", "coulomb-law", "force-properties"], "payload": {"question_id": "cuet-phy-elec-coulomb-45", "subtopic": "Properties of Coulomb''s force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The two properties mentioned in R (acts along joining line + depends only on distance) are the defining properties of a central force. R directly defines and explains why A is true.", "misconception": "Not recognising that R states the exact definition of a central force"}, {"option_key": "C", "hint": "R is a correct statement — Coulomb''s force does indeed act along the line joining charges and depends only on r.", "misconception": null}, {"option_key": "D", "hint": "A is correct — Coulomb''s force is indeed a central force, which is why angular momentum is conserved in classical electron orbits.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A sensitive gold-leaf electroscope can detect charge quantization at macroscopic scales.\nReason (R): The elementary charge e = 1.6 × 10⁻¹⁹ C is extremely small compared to charges typically encountered in daily life.", "explanation": "A is FALSE: at macroscopic scales, charges are so large (of order μC or more) that the discrete nature (quantization) of charge is not observable — charge appears continuous. R is TRUE: e is indeed extremely small compared to macroscopic charges, which is precisely why quantization is undetectable at large scales. Since A is incorrect and R is correct, the answer is D.", "correct_answer": "D", "concept_tags": ["quantization", "macroscopic-charge", "gold-leaf-electroscope"], "payload": {"question_id": "cuet-phy-elec-coulomb-46", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is incorrect — quantization cannot be detected at macroscopic scales because the elementary charge is too small relative to everyday charges.", "misconception": "Thinking quantization is easily observable with a gold-leaf electroscope"}, {"option_key": "B", "hint": "A is false, not true. A gold-leaf electroscope cannot detect individual electron charges.", "misconception": null}, {"option_key": "C", "hint": "R is actually correct — e = 1.6 × 10⁻¹⁹ C is indeed extremely small compared to typical macroscopic charges.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s force between two charges obeys Newton''s third law.\nReason (R): The force exerted by charge q₁ on q₂ is equal in magnitude and opposite in direction to the force exerted by q₂ on q₁.", "explanation": "Both A and R are correct. F₁₂ = kq₁q₂r̂₁₂/r² and F₂₁ = kq₁q₂r̂₂₁/r² = −F₁₂. This satisfies Newton''s third law (action = −reaction). R correctly states this property and directly explains A.", "correct_answer": "A", "concept_tags": ["newton-third-law", "action-reaction", "coulomb-law"], "payload": {"question_id": "cuet-phy-elec-coulomb-47", "subtopic": "Properties of Coulomb''s force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is the exact statement of Newton''s third law applied to Coulomb forces. Since A says Coulomb''s force obeys Newton''s third law, R is by definition the correct explanation.", "misconception": "Not seeing that R is just the restatement of Newton''s third law for this specific case"}, {"option_key": "C", "hint": "R is factually correct — by Coulomb''s law, F₁₂ = −F₂₁ always holds.", "misconception": null}, {"option_key": "D", "hint": "A is correct — Coulomb''s force is a conservative, central force that obeys Newton''s third law.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s law accurately predicts the force between two charged bodies of any shape and size.\nReason (R): Coulomb''s law is derived for point charges and works accurately only when the size of the charged bodies is much smaller than the distance between them.", "explanation": "A is FALSE: Coulomb''s law in its standard form F = kq₁q₂/r² is strictly valid only for point charges (or when bodies are very small compared to separation). For extended bodies, charge distribution matters and the simple formula is inadequate. R is TRUE: it correctly states the limitation. Since A is wrong and R is right, the answer is D.", "correct_answer": "D", "concept_tags": ["coulomb-law-limitations", "point-charge-approximation"], "payload": {"question_id": "cuet-phy-elec-coulomb-48", "subtopic": "Validity conditions of Coulomb''s law", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — Coulomb''s law does not work for bodies of any shape/size. For large or close conductors, charge redistribution invalidates the point-charge formula.", "misconception": "Thinking Coulomb''s law applies universally to all shapes"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — it accurately describes the point-charge requirement of Coulomb''s law.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric charge is an additive quantity — the total charge of a system is the algebraic sum of all individual charges.", "explanation": "This is TRUE. Additivity of charge means the total charge of a system equals the algebraic (not absolute) sum of all charges. For example, if a system has charges +5 μC and −3 μC, the total charge is +2 μC. This property, along with conservation and quantization, is a fundamental property of electric charge.", "correct_answer": "A", "concept_tags": ["additivity", "charge-properties", "algebraic-sum"], "payload": {"question_id": "cuet-phy-elec-coulomb-49", "subtopic": "Properties of electric charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Additivity of charge is a well-established property. Unlike some quantities (like mass in relativity), charge adds algebraically in all situations.", "misconception": "Confusing additivity of charge with non-additive quantities"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electrostatic force between two charges is independent of the presence of other charges nearby (superposition principle).", "explanation": "This is TRUE. The superposition principle states that the force between any two charges is given by Coulomb''s law regardless of the presence of other charges. The net force on a charge is the vector sum of individual pair-wise forces. Each pair interaction is unaffected by the existence of third charges.", "correct_answer": "A", "concept_tags": ["superposition", "independent-interaction", "pair-force"], "payload": {"question_id": "cuet-phy-elec-coulomb-50", "subtopic": "Superposition principle", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The superposition principle is a cornerstone of classical electrostatics. The Coulomb force between any pair depends only on those two charges and their separation.", "misconception": "Thinking nearby charges modify the force between a specific pair"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two point charges depends on the nature of the medium between them — it decreases when a dielectric is placed between them but increases when they are in vacuum.", "explanation": "This is partially misleading but essentially FALSE as stated. The statement implies the force ''increases in vacuum'' as if vacuum makes it stronger than some baseline — but vacuum IS the reference (maximum force). The force in any medium is F/K where K ≥ 1. The statement''s implication that force ''increases'' in vacuum is incorrect framing. The correct statement: force is maximum in vacuum and decreases in any dielectric medium.", "correct_answer": "B", "concept_tags": ["dielectric-effect", "medium-dependence", "vacuum"], "payload": {"question_id": "cuet-phy-elec-coulomb-51", "subtopic": "Coulomb''s law in different media", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The phrasing ''increases in vacuum'' is misleading. Force is maximum in vacuum — it doesn''t ''increase'' because vacuum is already the reference state (K=1). Any medium only reduces the force.", "misconception": "Thinking vacuum actively increases the force rather than being the baseline"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Quarks, which have charges of ±e/3 and ±2e/3, violate the principle of quantization of electric charge.", "explanation": "This is FALSE. Quarks do carry fractional charges (e/3 and 2e/3), but they never exist as free particles — they are always confined within hadrons (protons, neutrons, mesons) due to quark confinement. The principle of quantization of charge states that all freely observed charges are integral multiples of e. Quarks do not violate this because they are never observed in isolation.", "correct_answer": "B", "concept_tags": ["quarks", "quantization", "confinement"], "payload": {"question_id": "cuet-phy-elec-coulomb-52", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Quarks are always confined inside hadrons and never exist freely. The quantization principle applies to freely observable charge, not to quarks inside composite particles.", "misconception": "Thinking quark charges violate quantization because they are fractional"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charging method in Column I with its key characteristic in Column II:\n\nColumn I:\nA. Charging by friction\nB. Charging by conduction\nC. Charging by induction\nD. Charging by a Van de Graaff generator\n\nColumn II:\n1. Charge accumulation on a hollow sphere using a belt\n2. Both bodies acquire equal and opposite charges\n3. The charged body transfers charge to the uncharged body on contact\n4. The charged body induces charge separation without contact", "explanation": "Friction (A) involves rubbing two bodies — both acquire equal and opposite charges → A-2. Conduction (B) involves touching a charged body to an uncharged one — charge flows on contact → B-3. Induction (C) involves bringing a charged body near an uncharged conductor without contact → C-4. Van de Graaff generator (D) uses a moving belt to accumulate charge on a hollow metal sphere → D-1.", "correct_answer": "C", "concept_tags": ["charging-methods", "friction", "conduction", "induction"], "payload": {"question_id": "cuet-phy-elec-coulomb-53", "subtopic": "Methods of charging", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns ''charge transfer on contact'' (3) to friction and ''equal and opposite charges'' (2) to conduction. In friction, both bodies get equal opposite charges; conduction involves contact transfer.", "misconception": "Swapping friction and conduction characteristics"}, {"option_key": "B", "hint": "This assigns ''no contact'' (4) to conduction, but conduction requires physical contact.", "misconception": "Confusing conduction (contact required) with induction (no contact)"}, {"option_key": "D", "hint": "This assigns ''no contact'' (4) to friction, but friction requires vigorous rubbing (contact).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situation in Column I with the correct force expression in Column II:\n\nColumn I:\nA. Two charges q in vacuum at distance d\nB. Two charges q in medium (K=4) at distance d\nC. Two charges q in vacuum at distance 2d\nD. Charges 2q and q in vacuum at distance d\n\nColumn II:\n1. kq²/(4d²)\n2. 2kq²/d²\n3. kq²/(4d²)\n4. kq²/d²", "explanation": "A: F = kq²/d² → A-4. B: F = kq²/(Kd²) = kq²/(4d²) → B-1 (or B-3, since items 1 and 3 are identical). C: F = kq²/(2d)² = kq²/(4d²) → C-3 (or C-1). D: F = k(2q)(q)/d² = 2kq²/d² → D-2. Note: items 1 and 3 have the same expression, so B and C both map to kq²/(4d²).", "correct_answer": "B", "concept_tags": ["coulomb-law-variations", "dielectric", "distance-scaling"], "payload": {"question_id": "cuet-phy-elec-coulomb-54", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns 2kq²/d² to situation B (medium K=4), but a medium reduces the force, so B cannot give the largest force expression.", "misconception": "Thinking a dielectric increases the force"}, {"option_key": "C", "hint": "This assigns kq²/d² (full vacuum force) to two charges q in vacuum at 2d — but doubling distance reduces force by 4.", "misconception": "Ignoring the effect of doubling the distance"}, {"option_key": "D", "hint": "This maps D (charges 2q and q) to kq²/(4d²), but the product 2q×q = 2q² gives 2kq²/d², not kq²/4d².", "misconception": "Not computing the charge product correctly"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The minimum charge that can exist independently in nature is called the _____ charge, and its value is approximately _____.", "explanation": "The minimum independently existing charge is the elementary charge (e), with value approximately 1.6 × 10⁻¹⁹ C. This was first accurately measured by Robert Millikan in his oil-drop experiment (1909). All observable charges are integral multiples of this fundamental unit.", "correct_answer": "D", "concept_tags": ["elementary-charge", "millikan-experiment"], "payload": {"question_id": "cuet-phy-elec-coulomb-55", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "unit; 1 coulomb", "is_correct": false}, {"key": "B", "text": "fractional; 1.6 × 10⁻²⁰ C", "is_correct": false}, {"key": "C", "text": "atomic; 9.1 × 10⁻³¹ kg", "is_correct": false}, {"key": "D", "text": "elementary; 1.6 × 10⁻¹⁹ C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is a macroscopic unit of charge (≈6.25 × 10¹⁸ electron charges), far too large to be the minimum charge.", "misconception": "Confusing the SI unit with the fundamental minimum"}, {"option_key": "B", "hint": "1.6 × 10⁻²⁰ C is ten times smaller than the actual elementary charge. Also, charge is not called ''fractional charge''.", "misconception": "Incorrect value of elementary charge"}, {"option_key": "C", "hint": "9.1 × 10⁻³¹ kg is the mass of an electron, not a charge. The units are wrong (kg vs C).", "misconception": "Confusing electron mass with electron charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The electrostatic force between two charges of 1 C each placed 1 m apart in vacuum is approximately _____ N.", "explanation": "F = kq₁q₂/r² = 9 × 10⁹ × 1 × 1 / 1² = 9 × 10⁹ N. This enormous force (about 9 billion newtons!) shows that 1 C is an extremely large amount of charge. For reference, this force is roughly equal to the weight of one million tonnes.", "correct_answer": "C", "concept_tags": ["coulomb-law", "numerical", "force-magnitude"], "payload": {"question_id": "cuet-phy-elec-coulomb-56", "subtopic": "Magnitude of electrostatic force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "9 × 10⁶", "is_correct": false}, {"key": "B", "text": "9 × 10¹²", "is_correct": false}, {"key": "C", "text": "9 × 10⁹", "is_correct": true}, {"key": "D", "text": "1.6 × 10⁻¹⁹", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "9 × 10⁶ is three orders of magnitude too small. The Coulomb constant k = 9 × 10⁹, and with unit charges at 1 m, F = k directly.", "misconception": "Using wrong exponent for Coulomb''s constant"}, {"option_key": "B", "hint": "9 × 10¹² is three orders too large. Since both charges are 1 C and distance is 1 m, F simply equals k = 9 × 10⁹.", "misconception": "Adding extra factors beyond the formula"}, {"option_key": "D", "hint": "1.6 × 10⁻¹⁹ is the value of the elementary charge in coulombs, not a force value.", "misconception": "Confusing charge with force"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student performs Millikan''s oil drop experiment. She observes a tiny oil drop of mass 4.9 × 10⁻¹⁵ kg suspended motionless between two horizontal plates separated by 2 cm, with a potential difference of 980 V applied between them. Taking g = 9.8 m/s², the charge on the oil drop is approximately:", "explanation": "For the drop to be stationary, the upward electric force must balance gravity: qE = mg. Electric field E = V/d = 980/0.02 = 49000 V/m. Charge q = mg/E = (4.9 × 10⁻¹⁵ × 9.8) / 49000 = 48.02 × 10⁻¹⁵ / 49000 = 9.8 × 10⁻¹⁹ C. This is approximately 6e (6 × 1.6 × 10⁻¹⁹ = 9.6 × 10⁻¹⁹ C), confirming quantization — the charge is an integer multiple of e.", "correct_answer": "A", "concept_tags": ["millikan-experiment", "charge-quantization", "force-balance"], "payload": {"question_id": "cuet-phy-elec-coulomb-57", "subtopic": "Millikan''s oil drop experiment", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "9.8 × 10⁻¹⁹ C (≈ 6e)", "is_correct": true}, {"key": "B", "text": "1.6 × 10⁻¹⁹ C (= e)", "is_correct": false}, {"key": "C", "text": "4.9 × 10⁻¹⁹ C (≈ 3e)", "is_correct": false}, {"key": "D", "text": "3.2 × 10⁻¹⁸ C (= 20e)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1.6 × 10⁻¹⁹ C (single electron charge) would require a much lighter drop or much stronger field to achieve equilibrium with the given values.", "misconception": "Assuming the drop carries only one electron charge without calculating"}, {"option_key": "C", "hint": "4.9 × 10⁻¹⁹ is half the correct answer — likely from a factor-of-2 error in the calculation (perhaps using d = 4 cm instead of 2 cm).", "misconception": "Error in the plate separation value"}, {"option_key": "D", "hint": "3.2 × 10⁻¹⁸ is about 3× too large — possibly from using E = V (not V/d) or a unit conversion error.", "misconception": "Forgetting to divide voltage by distance to get electric field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "In an advanced electrostatics lab, two identical insulating spheres A and B carry charges +6Q and −2Q respectively. They are touched together, separated, and then sphere B is touched to an identical uncharged sphere C. After all separations, the charges on A, B, and C respectively are:", "explanation": "Step 1: A (+6Q) and B (−2Q) touch → total = 4Q, each gets +2Q. After separation: A = +2Q, B = +2Q. Step 2: B (+2Q) touches C (0) → total = 2Q, each gets +Q. After separation: B = +Q, C = +Q. Final: A = +2Q, B = +Q, C = +Q.", "correct_answer": "D", "concept_tags": ["charge-sharing", "multiple-steps", "conductors"], "payload": {"question_id": "cuet-phy-elec-coulomb-58", "subtopic": "Charge redistribution", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "+2Q, +2Q, 0", "is_correct": false}, {"key": "B", "text": "+3Q, +Q/2, +Q/2", "is_correct": false}, {"key": "C", "text": "+4Q/3, +4Q/3, +4Q/3", "is_correct": false}, {"key": "D", "text": "+2Q, +Q, +Q", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This only accounts for step 1 (A and B sharing charge) but ignores step 2 (B touching C).", "misconception": "Forgetting the second touching step"}, {"option_key": "B", "hint": "+3Q total ≠ 4Q total. The total charge must be conserved at +6Q + (−2Q) = +4Q throughout.", "misconception": "Arithmetic error in charge conservation"}, {"option_key": "C", "hint": "This assumes all three spheres share charge equally, but A was separated before B touched C. A doesn''t participate in the second sharing.", "misconception": "Assuming all three spheres share charge simultaneously"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps of charging a metal sphere by induction in the correct sequence:\n\n1. Ground the sphere (connect to earth)\n2. Bring a positively charged rod near the sphere (without touching)\n3. Remove the grounding connection\n4. Remove the charged rod\n5. Negative charge remains on the sphere", "explanation": "Correct sequence: First bring the charged rod near (2) → this induces charge separation. Then ground the sphere (1) → positive charges flow to earth, leaving excess negative. Remove ground (3) → excess negative charge is trapped. Remove the rod (4) → negative charge redistributes uniformly. Result: sphere is negatively charged (5).", "correct_answer": "C", "concept_tags": ["induction-charging", "sequence", "grounding"], "payload": {"question_id": "cuet-phy-elec-coulomb-59", "subtopic": "Charging by induction", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "1 → 2 → 3 → 4 → 5", "is_correct": false}, {"key": "B", "text": "2 → 3 → 1 → 4 → 5", "is_correct": false}, {"key": "C", "text": "2 → 1 → 3 → 4 → 5", "is_correct": true}, {"key": "D", "text": "1 → 2 → 4 → 3 → 5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Grounding first (step 1) without the charged rod nearby has no effect — there''s no induced charge to drain. The rod must be brought close first.", "misconception": "Grounding before bringing the inducing charge"}, {"option_key": "B", "hint": "Removing ground (step 3) before connecting it (step 1) is illogical. You must ground first, then remove the ground.", "misconception": "Mixing up the order of grounding and ungrounding"}, {"option_key": "D", "hint": "Removing the rod (step 4) before removing the ground (step 3) would allow the trapped negative charge to flow back to earth, leaving the sphere uncharged.", "misconception": "Not realising that the ground must be removed BEFORE the rod"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following discoveries/developments in the history of electrostatics in chronological order:\n\n1. Millikan''s oil drop experiment (precise measurement of e)\n2. Coulomb''s torsion balance experiment\n3. Benjamin Franklin''s kite experiment\n4. Discovery of the electron by J.J. Thomson", "explanation": "Chronological order: Benjamin Franklin''s kite experiment (1752) → Coulomb''s torsion balance (1785) → J.J. Thomson discovers the electron (1897) → Millikan''s oil drop experiment (1909). So the sequence is 3 → 2 → 4 → 1.", "correct_answer": "B", "concept_tags": ["history-of-physics", "chronological-order", "electrostatics"], "payload": {"question_id": "cuet-phy-elec-coulomb-60", "subtopic": "Historical development", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "2 → 3 → 4 → 1", "is_correct": false}, {"key": "B", "text": "3 → 2 → 4 → 1", "is_correct": true}, {"key": "C", "text": "3 → 2 → 1 → 4", "is_correct": false}, {"key": "D", "text": "1 → 4 → 2 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s experiment (1785) came after Franklin''s (1752), not before. Franklin predated Coulomb by about 33 years.", "misconception": "Placing Coulomb before Franklin"}, {"option_key": "C", "hint": "Millikan (1909) came after Thomson (1897), not before. Millikan measured the charge of the electron that Thomson had discovered.", "misconception": "Thinking Millikan''s experiment preceded Thomson''s discovery of the electron"}, {"option_key": "D", "hint": "This puts the most recent (Millikan, 1909) first and the earliest (Franklin, 1752) last — completely reversed chronology.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Bohr''s model, the angular momentum of an electron in the nth orbit of a hydrogen atom is:", "explanation": "Bohr''s quantization postulate states that the angular momentum of an electron in a stationary orbit is an integral multiple of h/2π. That is, L = mvr = nh/2π, where n is the principal quantum number (n = 1, 2, 3, ...). This was a key postulate that explained the stability of atoms.", "correct_answer": "A", "concept_tags": ["bohr-model", "angular-momentum-quantization", "bohr-postulate"], "payload": {"question_id": "cuet-phy-atom-bohr-01", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "nh/2π", "is_correct": true}, {"key": "B", "text": "nh/π", "is_correct": false}, {"key": "C", "text": "n²h/2π", "is_correct": false}, {"key": "D", "text": "nh/4π", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is twice the correct value. Bohr''s quantization condition has 2π in the denominator, not π.", "misconception": "Forgetting the factor of 2 in 2π"}, {"option_key": "C", "hint": "Angular momentum is proportional to n, not n². The n² dependence applies to orbital radius, not angular momentum.", "misconception": "Confusing radius formula (n² dependence) with angular momentum formula (n dependence)"}, {"option_key": "D", "hint": "The denominator is 2π (from ħ = h/2π), not 4π. The factor 4π appears in Coulomb''s law, not in the angular momentum quantization.", "misconception": "Mixing up constants from different formulas"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The radius of the first Bohr orbit of hydrogen atom (Bohr radius) is approximately:", "explanation": "The Bohr radius a₀ is the radius of the first orbit (n = 1) of the hydrogen atom (Z = 1). Its value is a₀ = ε₀h²/(πme²) ≈ 0.529 Å = 0.529 × 10⁻¹⁰ m. This is a fundamental constant used as the unit of length in atomic physics.", "correct_answer": "B", "concept_tags": ["bohr-radius", "hydrogen-atom", "first-orbit"], "payload": {"question_id": "cuet-phy-atom-bohr-02", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "0.329 Å", "is_correct": false}, {"key": "B", "text": "0.529 Å", "is_correct": true}, {"key": "C", "text": "1.058 Å", "is_correct": false}, {"key": "D", "text": "2.116 Å", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value is not standard. The Bohr radius is a well-known constant equal to 0.529 Å.", "misconception": "Recalling an incorrect numerical value"}, {"option_key": "C", "hint": "1.058 Å = 2 × 0.529 Å. This would be the radius of the first orbit for a hypothetical scenario, not the standard Bohr radius.", "misconception": "Doubling the Bohr radius inadvertently"}, {"option_key": "D", "hint": "2.116 Å = 4 × 0.529 Å = 0.529 × 2². This is actually the radius of the second Bohr orbit (n = 2) for hydrogen.", "misconception": "Confusing the second orbit radius with the first orbit radius"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In Rutherford''s alpha-particle scattering experiment, most of the alpha particles pass through the gold foil without any deflection because:", "explanation": "Rutherford''s experiment showed that most alpha particles passed straight through the gold foil with little or no deflection. This is because most of the atom is empty space — the nucleus occupies an extremely small fraction (about 10⁻¹⁵ m in diameter compared to 10⁻¹⁰ m for the atom). Hence, most particles never come close to the nucleus.", "correct_answer": "C", "concept_tags": ["rutherford-scattering", "nuclear-model", "alpha-particle"], "payload": {"question_id": "cuet-phy-atom-bohr-03", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "understand", "options": [{"key": "A", "text": "The nucleus has no charge", "is_correct": false}, {"key": "B", "text": "Alpha particles are much heavier than gold atoms", "is_correct": false}, {"key": "C", "text": "Most of the space inside an atom is empty", "is_correct": true}, {"key": "D", "text": "Alpha particles have very high kinetic energy", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The gold nucleus has a charge of +79e. In fact, it is the nuclear charge that causes the deflection of those alpha particles that pass close to the nucleus.", "misconception": "Believing the nucleus is electrically neutral"}, {"option_key": "B", "hint": "Gold atoms (mass number 197) are actually much heavier than alpha particles (mass number 4). This is why alpha particles bounce back when they hit the nucleus head-on.", "misconception": "Reversing the relative masses of alpha particles and gold atoms"}, {"option_key": "D", "hint": "While alpha particles do have high kinetic energy, this alone does not explain why most pass undeflected. The reason is the emptiness of the atom.", "misconception": "Attributing undeflected passage to kinetic energy rather than atomic structure"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The Lyman series of the hydrogen spectrum lies in which region of the electromagnetic spectrum?", "explanation": "The Lyman series corresponds to transitions from higher energy levels (n₂ = 2, 3, 4, ...) to the ground state (n₁ = 1). These transitions involve the largest energy differences and produce photons in the ultraviolet region. The Balmer series lies in the visible region, while Paschen, Brackett, and Pfund series lie in the infrared region.", "correct_answer": "D", "concept_tags": ["lyman-series", "hydrogen-spectrum", "ultraviolet"], "payload": {"question_id": "cuet-phy-atom-bohr-04", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "Visible region", "is_correct": false}, {"key": "B", "text": "Infrared region", "is_correct": false}, {"key": "C", "text": "Microwave region", "is_correct": false}, {"key": "D", "text": "Ultraviolet region", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The visible region corresponds to the Balmer series (transitions to n = 2), not the Lyman series.", "misconception": "Confusing Lyman series with Balmer series"}, {"option_key": "B", "hint": "The infrared region corresponds to the Paschen (n₁ = 3), Brackett (n₁ = 4), and Pfund (n₁ = 5) series.", "misconception": "Confusing Lyman series with Paschen/Brackett/Pfund series"}, {"option_key": "C", "hint": "Microwave radiation has much lower energy than the transitions in the hydrogen atom spectral series.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The energy of an electron in the third Bohr orbit of hydrogen atom is:", "explanation": "The energy of an electron in the nth orbit of a hydrogen-like atom is Eₙ = −13.6Z²/n² eV. For hydrogen (Z = 1) in the third orbit (n = 3): E₃ = −13.6 × 1²/3² = −13.6/9 ≈ −1.51 eV.", "correct_answer": "B", "concept_tags": ["energy-levels", "hydrogen-atom", "bohr-model"], "payload": {"question_id": "cuet-phy-atom-bohr-05", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "−3.40 eV", "is_correct": false}, {"key": "B", "text": "−1.51 eV", "is_correct": true}, {"key": "C", "text": "−0.85 eV", "is_correct": false}, {"key": "D", "text": "−13.6 eV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "−3.40 eV = −13.6/4 = −13.6/2². This corresponds to n = 2 (second orbit), not n = 3.", "misconception": "Using n = 2 instead of n = 3"}, {"option_key": "C", "hint": "−0.85 eV = −13.6/16 = −13.6/4². This corresponds to n = 4 (fourth orbit), not n = 3.", "misconception": "Using n = 4 instead of n = 3"}, {"option_key": "D", "hint": "−13.6 eV is the energy of the ground state (n = 1). For n = 3, you must divide by n² = 9.", "misconception": "Forgetting to divide by n²"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the radii of the first three Bohr orbits of hydrogen atom is:", "explanation": "The radius of the nth Bohr orbit is rₙ = n²a₀/Z. For hydrogen (Z = 1): r₁ = a₀, r₂ = 4a₀, r₃ = 9a₀. Therefore, r₁ : r₂ : r₃ = 1 : 4 : 9, which follows the n² dependence.", "correct_answer": "C", "concept_tags": ["bohr-radius", "orbit-radius", "n-squared-dependence"], "payload": {"question_id": "cuet-phy-atom-bohr-06", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "1 : 2 : 3", "is_correct": false}, {"key": "B", "text": "1 : 8 : 27", "is_correct": false}, {"key": "C", "text": "1 : 4 : 9", "is_correct": true}, {"key": "D", "text": "1 : 1/4 : 1/9", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The ratio 1:2:3 corresponds to a linear (n) dependence. Bohr orbit radius depends on n², not n.", "misconception": "Assuming radius is proportional to n instead of n²"}, {"option_key": "B", "hint": "The ratio 1:8:27 corresponds to an n³ dependence. The radius depends on n², not n³.", "misconception": "Using n³ instead of n²"}, {"option_key": "D", "hint": "This is the inverse-square ratio (1/n²). The radius increases as n², not decreases. This ratio describes how energy varies with n.", "misconception": "Confusing the energy level formula (−13.6/n²) with the radius formula (n²a₀)"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Balmer series of hydrogen is 656.3 nm. The wavelength of the second line of the Balmer series is approximately:", "explanation": "For the Balmer series, n₁ = 2. The first line: 1/λ₁ = R(1/4 − 1/9) = R(5/36). The second line: 1/λ₂ = R(1/4 − 1/16) = R(3/16). Therefore λ₂/λ₁ = (5/36)/(3/16) = (5 × 16)/(36 × 3) = 80/108 = 20/27. So λ₂ = 656.3 × (20/27) ≈ 486.1 nm.", "correct_answer": "A", "concept_tags": ["balmer-series", "rydberg-formula", "wavelength-calculation"], "payload": {"question_id": "cuet-phy-atom-bohr-07", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "486.1 nm", "is_correct": true}, {"key": "B", "text": "434.0 nm", "is_correct": false}, {"key": "C", "text": "364.6 nm", "is_correct": false}, {"key": "D", "text": "410.2 nm", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "434.0 nm corresponds to the third Balmer line (n = 5 to n = 2), not the second line.", "misconception": "Selecting the wrong line of the series"}, {"option_key": "C", "hint": "364.6 nm is close to the series limit of the Balmer series (n = ∞ to n = 2), not the second line.", "misconception": "Confusing a specific line with the series limit"}, {"option_key": "D", "hint": "410.2 nm corresponds to the fourth Balmer line (n = 6 to n = 2), not the second line.", "misconception": "Selecting the wrong line of the series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ionization energy of the hydrogen atom in the ground state is 13.6 eV. The energy required to ionize a hydrogen atom from its first excited state is:", "explanation": "The first excited state corresponds to n = 2. The energy of this state is E₂ = −13.6/2² = −13.6/4 = −3.4 eV. Ionization means removing the electron to E = 0 (n = ∞). Therefore, the ionization energy from the first excited state = 0 − (−3.4) = 3.4 eV.", "correct_answer": "C", "concept_tags": ["ionization-energy", "excited-state", "energy-levels"], "payload": {"question_id": "cuet-phy-atom-bohr-08", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 eV", "is_correct": false}, {"key": "B", "text": "6.8 eV", "is_correct": false}, {"key": "C", "text": "3.4 eV", "is_correct": true}, {"key": "D", "text": "1.51 eV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "13.6 eV is the ionization energy from the ground state (n = 1), not from the first excited state (n = 2).", "misconception": "Using ground state instead of first excited state"}, {"option_key": "B", "hint": "6.8 eV = 13.6/2, which incorrectly divides by n instead of n². The energy varies as 1/n².", "misconception": "Dividing ionization energy by n instead of n²"}, {"option_key": "D", "hint": "1.51 eV = 13.6/9 corresponds to the energy of the n = 3 level. The first excited state is n = 2, not n = 3.", "misconception": "Confusing second excited state (n = 3) with first excited state (n = 2)"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The speed of an electron in the first Bohr orbit of hydrogen atom is v₁. The speed of the electron in the third orbit will be:", "explanation": "The speed of an electron in the nth Bohr orbit is given by vₙ = v₁Z/n. For hydrogen (Z = 1) in the third orbit (n = 3): v₃ = v₁/3. The electron speed decreases as 1/n because for larger orbits, the Coulomb force is weaker and the electron moves more slowly.", "correct_answer": "D", "concept_tags": ["orbital-velocity", "bohr-model", "velocity-quantization"], "payload": {"question_id": "cuet-phy-atom-bohr-09", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "3v₁", "is_correct": false}, {"key": "B", "text": "v₁/9", "is_correct": false}, {"key": "C", "text": "9v₁", "is_correct": false}, {"key": "D", "text": "v₁/3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This suggests speed increases with n, but in Bohr''s model, the electron moves slower in higher orbits. Speed is inversely proportional to n.", "misconception": "Assuming speed increases with orbit number"}, {"option_key": "B", "hint": "v₁/9 = v₁/3² implies speed varies as 1/n². However, speed varies as 1/n, not 1/n².", "misconception": "Confusing 1/n dependence of velocity with 1/n² dependence of energy"}, {"option_key": "C", "hint": "This would mean the speed increases as n², which contradicts Bohr''s model where higher orbits have lower speeds.", "misconception": "Confusing velocity with radius formula"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The total number of spectral lines emitted when a hydrogen atom de-excites from the nth energy level to the ground state is given by n(n−1)/2. If a sample of hydrogen atoms is excited to the 4th energy level, how many spectral lines can be observed?", "explanation": "When hydrogen atoms are excited to the 4th energy level (n = 4), they can de-excite through various transitions. The total number of spectral lines = n(n−1)/2 = 4(4−1)/2 = 4 × 3/2 = 6. These lines correspond to transitions: 4→3, 4→2, 4→1, 3→2, 3→1, and 2→1.", "correct_answer": "B", "concept_tags": ["spectral-lines", "energy-transitions", "hydrogen-spectrum"], "payload": {"question_id": "cuet-phy-atom-bohr-10", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "4", "is_correct": false}, {"key": "B", "text": "6", "is_correct": true}, {"key": "C", "text": "10", "is_correct": false}, {"key": "D", "text": "3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This might come from thinking only about transitions from n = 4 directly to lower levels (4→3, 4→2, 4→1), but that gives only 3 lines from level 4. You must also count transitions between intermediate levels.", "misconception": "Counting only transitions originating from the highest level"}, {"option_key": "C", "hint": "10 = 5(5−1)/2, which would be the answer for n = 5, not n = 4.", "misconception": "Using the wrong value of n in the formula"}, {"option_key": "D", "hint": "3 counts only the direct transitions from n = 4 (to n = 3, 2, and 1), ignoring transitions like 3→2, 3→1, and 2→1.", "misconception": "Counting only transitions from the highest level to each lower level"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The radius of the innermost orbit of a hydrogen atom is 0.53 Å. The radius of the third orbit of He⁺ ion is:", "explanation": "The radius of the nth orbit for a hydrogen-like atom is rₙ = n²a₀/Z. For He⁺ ion (Z = 2) in the third orbit (n = 3): r₃ = 3² × 0.53/2 = 9 × 0.53/2 = 4.77/2 = 2.385 Å ≈ 2.38 Å. The radius increases as n² but decreases as 1/Z.", "correct_answer": "D", "concept_tags": ["hydrogen-like-atom", "orbit-radius", "helium-ion"], "payload": {"question_id": "cuet-phy-atom-bohr-11", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "4.77 Å", "is_correct": false}, {"key": "B", "text": "0.265 Å", "is_correct": false}, {"key": "C", "text": "1.06 Å", "is_correct": false}, {"key": "D", "text": "2.38 Å", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4.77 Å = 9 × 0.53 Å is the radius of the third orbit of hydrogen (Z = 1). For He⁺, you must also divide by Z = 2.", "misconception": "Forgetting to account for Z in the radius formula for hydrogen-like ions"}, {"option_key": "B", "hint": "0.265 Å = 0.53/2 is the first Bohr orbit radius of He⁺. This does not account for n = 3.", "misconception": "Using n = 1 instead of n = 3"}, {"option_key": "C", "hint": "1.06 Å = 2 × 0.53 Å. This might result from using n = 2 for hydrogen or an incorrect formula.", "misconception": "Arithmetic error or using wrong quantum number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following transitions in a hydrogen atom produces a photon of the shortest wavelength?", "explanation": "Shorter wavelength means higher energy of the emitted photon. The energy of a photon emitted during a transition is ΔE = 13.6(1/n₁² − 1/n₂²) eV. The transition n = 2 to n = 1 gives ΔE = 13.6(1 − 1/4) = 13.6 × 3/4 = 10.2 eV. The transition n = 5 to n = 4 gives ΔE = 13.6(1/16 − 1/25) = 13.6 × 9/400 = 0.306 eV. The transition n = 6 to n = 5 gives ΔE = 13.6(1/25 − 1/36) = 13.6 × 11/900 = 0.166 eV. The transition n = 3 to n = 2 gives ΔE = 13.6(1/4 − 1/9) = 13.6 × 5/36 = 1.89 eV. The largest energy difference (10.2 eV) corresponds to n = 2 → n = 1, giving the shortest wavelength.", "correct_answer": "A", "concept_tags": ["energy-transition", "photon-wavelength", "lyman-series"], "payload": {"question_id": "cuet-phy-atom-bohr-12", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "n = 2 to n = 1", "is_correct": true}, {"key": "B", "text": "n = 5 to n = 4", "is_correct": false}, {"key": "C", "text": "n = 6 to n = 5", "is_correct": false}, {"key": "D", "text": "n = 3 to n = 2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Transitions between high-n levels involve very small energy differences because energy levels get closer together at higher n. This gives a long wavelength.", "misconception": "Thinking higher quantum numbers give shorter wavelengths"}, {"option_key": "C", "hint": "The transition n = 6 to n = 5 involves the smallest energy gap among all the options, producing the longest wavelength photon.", "misconception": "Confusing longest and shortest wavelength"}, {"option_key": "D", "hint": "While this transition (first Balmer line) has a significant energy gap, it is much smaller than the n = 2 to n = 1 transition (10.2 eV vs 1.89 eV).", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Bohr model successfully explains the spectra of hydrogen and hydrogen-like atoms but fails for multi-electron atoms.\nReason (R): The Bohr model does not account for electron-electron interactions and treats the problem as a single-electron system.", "explanation": "The Assertion is correct — the Bohr model works well for single-electron systems (H, He⁺, Li²⁺, etc.) but fails for multi-electron atoms like helium. The Reason is also correct and correctly explains why: the Bohr model considers only the Coulomb interaction between the nucleus and one electron, ignoring electron-electron repulsion. In multi-electron atoms, inter-electronic repulsion significantly affects energy levels, and the Bohr model has no provision for this. Hence both A and R are correct, and R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["bohr-model-limitations", "multi-electron-atoms", "electron-interaction"], "payload": {"question_id": "cuet-phy-atom-bohr-13", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly addresses why the Bohr model fails for multi-electron atoms — it ignores electron-electron interactions. This is the actual cause, making R the correct explanation of A.", "misconception": "Failing to see the causal link between electron-electron interaction and the model''s failure for multi-electron atoms"}, {"option_key": "C", "hint": "The Reason is factually correct. The Bohr model indeed treats only one electron interacting with the nucleus and has no mechanism for electron-electron repulsion.", "misconception": "Incorrectly believing the Bohr model accounts for electron-electron interactions"}, {"option_key": "D", "hint": "The Assertion is a well-established fact. The Bohr model accurately predicts spectra of H, He⁺, Li²⁺ but not of He, Li, etc.", "misconception": "Incorrectly thinking the Bohr model works for all atoms"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): In the Bohr model, the electron in a hydrogen atom does not radiate energy while revolving in a stationary orbit, even though it is an accelerating charge.\nReason (R): According to classical electromagnetic theory, an accelerating charged particle always radiates energy.", "explanation": "The Assertion is correct — Bohr''s second postulate explicitly states that electrons in stationary orbits do not radiate energy despite undergoing centripetal acceleration. This was a revolutionary departure from classical theory. The Reason is also correct — classical electromagnetic theory (Larmor formula) does predict that accelerating charges radiate energy. However, the Reason actually contradicts (or at least does not explain) the Assertion. Bohr''s postulate was introduced precisely to override this classical prediction. The Reason explains why the Bohr model had to introduce this postulate, but it does not explain why the electron does not radiate — it merely states the classical expectation. Both statements are true but R does not correctly explain A; rather, A is a postulate that overrides the classical prediction in R.", "correct_answer": "B", "concept_tags": ["bohr-postulates", "stationary-orbits", "classical-electrodynamics", "accelerating-charge"], "payload": {"question_id": "cuet-phy-atom-bohr-14", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R states the classical prediction that accelerating charges radiate, but A says the electron does NOT radiate. R describes what classical theory predicts (radiation), which is opposite to what A claims (no radiation). R cannot be the explanation of A.", "misconception": "Assuming R explains A when R actually describes the classical expectation that Bohr''s postulate overrides"}, {"option_key": "C", "hint": "The Reason is factually correct. Classical electromagnetic theory does predict that accelerating charges radiate energy (Larmor formula). This is a well-established result.", "misconception": "Confusing the Bohr postulate with classical electromagnetic theory"}, {"option_key": "D", "hint": "The Assertion is correct. It is a direct statement of Bohr''s second postulate about stationary orbits.", "misconception": "Thinking Bohr''s postulate is incorrect"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I (Spectral series) with Column II (Lower energy level n₁):\n\nColumn I: (P) Lyman series, (Q) Balmer series, (R) Paschen series, (S) Brackett series\n\nColumn II: (1) n₁ = 3, (2) n₁ = 1, (3) n₁ = 4, (4) n₁ = 2", "explanation": "The spectral series of hydrogen are named after their discoverers and are defined by the lower energy level: Lyman series has n₁ = 1 (UV region), Balmer series has n₁ = 2 (visible region), Paschen series has n₁ = 3 (IR region), Brackett series has n₁ = 4 (IR region). Therefore: P→2, Q→4, R→1, S→3.", "correct_answer": "C", "concept_tags": ["spectral-series", "hydrogen-spectrum", "energy-transitions"], "payload": {"question_id": "cuet-phy-atom-bohr-15", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "D", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This option assigns P (Lyman) to n₁ = 3, but the Lyman series corresponds to transitions to n₁ = 1, the ground state.", "misconception": "Not knowing that Lyman series terminates at the ground state"}, {"option_key": "B", "hint": "This swaps the Balmer and Paschen series assignments. Balmer corresponds to n₁ = 2 (not 1) and Paschen to n₁ = 3 (not 4).", "misconception": "Confusing the order of spectral series"}, {"option_key": "D", "hint": "This assigns Lyman to n₁ = 4 and Brackett to n₁ = 1, which is reversed. Lyman is the first series (n₁ = 1) and Brackett is the fourth (n₁ = 4).", "misconception": "Reversing the order of spectral series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I (Physical quantity in Bohr model) with Column II (Dependence on principal quantum number n for hydrogen atom):\n\nColumn I: (P) Orbital radius, (Q) Electron speed, (R) Total energy, (S) Time period of revolution\n\nColumn II: (1) Proportional to n³, (2) Proportional to n², (3) Inversely proportional to n², (4) Inversely proportional to n", "explanation": "In the Bohr model for hydrogen (Z = 1): Orbital radius rₙ ∝ n² (P→2). Electron speed vₙ ∝ 1/n (Q→4). Total energy Eₙ = −13.6/n² ∝ −1/n², so |Eₙ| ∝ 1/n² (R→3). Time period Tₙ = 2πrₙ/vₙ ∝ n²/(1/n) = n³ (S→1). Therefore the correct matching is P→2, Q→4, R→3, S→1.", "correct_answer": "D", "concept_tags": ["bohr-model", "quantum-number-dependence", "orbital-properties"], "payload": {"question_id": "cuet-phy-atom-bohr-16", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "B", "text": "P→1, Q→4, R→3, S→2", "is_correct": false}, {"key": "C", "text": "P→2, Q→4, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→2, Q→4, R→3, S→1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This assigns Q (electron speed) to 1/n² and R (energy) to 1/n. Speed varies as 1/n, not 1/n², and energy magnitude varies as 1/n², not 1/n.", "misconception": "Swapping the n-dependence of speed and energy"}, {"option_key": "B", "hint": "This assigns P (radius) to n³ and S (time period) to n². Radius varies as n² and time period as n³, not the other way around.", "misconception": "Confusing the n-dependence of radius and time period"}, {"option_key": "C", "hint": "This assigns R (energy) to n³ and S (time period) to 1/n². Energy magnitude varies as 1/n² and time period as n³.", "misconception": "Incorrectly matching energy and time period dependencies"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In Bohr''s model of the hydrogen atom, the frequency of radiation emitted when an electron jumps from a higher orbit to a lower orbit equals the difference in energy of the two orbits divided by Planck''s constant.", "explanation": "This is TRUE. According to Bohr''s frequency condition (third postulate), when an electron transitions from a higher energy level E₂ to a lower energy level E₁, a photon is emitted with frequency ν = (E₂ − E₁)/h, where h is Planck''s constant. This is a direct statement of energy conservation: the photon carries away the exact energy difference between the two levels.", "correct_answer": "A", "concept_tags": ["bohr-frequency-condition", "photon-emission", "energy-conservation"], "payload": {"question_id": "cuet-phy-atom-bohr-17", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a direct expression of Bohr''s third postulate: hν = E₂ − E₁, which gives ν = (E₂ − E₁)/h. This is a fundamental result.", "misconception": "Confusing Bohr''s frequency condition with some other relationship"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In the Bohr model, the electron in a hydrogen atom can revolve in any orbit as long as its energy is negative.", "explanation": "This is FALSE. In the Bohr model, the electron cannot revolve in any arbitrary orbit. It can only exist in specific quantized orbits where the angular momentum is an integral multiple of h/2π (i.e., L = nh/2π where n = 1, 2, 3, ...). This quantization condition restricts the electron to only certain discrete orbits, not all orbits with negative energy.", "correct_answer": "B", "concept_tags": ["quantized-orbits", "bohr-postulates", "angular-momentum"], "payload": {"question_id": "cuet-phy-atom-bohr-18", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The key feature of Bohr''s model is quantization — the electron is restricted to specific orbits where L = nh/2π. A continuous range of orbits with negative energy would be the classical model, which Bohr rejected.", "misconception": "Confusing the classical model (continuous orbits) with Bohr''s quantized model"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The maximum number of spectral lines that can be emitted when a hydrogen atom in the 5th excited state de-excites to the ground state is _____.", "explanation": "The 5th excited state corresponds to n = 6 (since the ground state is n = 1, the first excited state is n = 2, and so on). The number of spectral lines emitted when an atom de-excites from level n to the ground state is n(n−1)/2 = 6(6−1)/2 = 6 × 5/2 = 15. These arise from all possible downward transitions between levels 6, 5, 4, 3, 2, and 1.", "correct_answer": "C", "concept_tags": ["spectral-lines", "excited-state", "de-excitation"], "payload": {"question_id": "cuet-phy-atom-bohr-19", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "5", "is_correct": false}, {"key": "C", "text": "15", "is_correct": true}, {"key": "D", "text": "6", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 = 5(5−1)/2, which would apply if the atom were in the 4th excited state (n = 5). The 5th excited state is n = 6.", "misconception": "Confusing the excited state number with the principal quantum number (n = 5 is the 4th excited state, not the 5th)"}, {"option_key": "B", "hint": "5 would be the number of direct transitions from n = 6 to lower levels (6→5, 6→4, 6→3, 6→2, 6→1), ignoring intermediate transitions.", "misconception": "Counting only transitions from the highest level"}, {"option_key": "D", "hint": "6 = 4(4−1)/2, which applies to n = 4 (3rd excited state). The 5th excited state has n = 6.", "misconception": "Using the wrong principal quantum number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-bohr", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A research team is studying a distant star''s atmosphere by analyzing its absorption spectrum. They observe a series of dark lines corresponding to the Balmer series of hydrogen. The wavelength of the line corresponding to the transition from n = 4 to n = 2 is measured to be 486.1 nm. Using the Rydberg formula, if the Rydberg constant R = 1.097 × 10⁷ m⁻¹, calculate the wavelength of the Balmer series limit (n = ∞ to n = 2) and identify its spectral region.", "explanation": "The Balmer series limit corresponds to the transition from n₂ = ∞ to n₁ = 2. Using the Rydberg formula: 1/λ = R(1/n₁² − 1/n₂²) = R(1/4 − 1/∞) = R/4. Therefore λ = 4/R = 4/(1.097 × 10⁷) = 3.646 × 10⁻⁷ m = 364.6 nm. This wavelength (364.6 nm) lies in the ultraviolet region of the electromagnetic spectrum, just below the visible violet limit (~380 nm). The Balmer series limit marks the shortest wavelength (highest energy) transition in the Balmer series.", "correct_answer": "D", "concept_tags": ["rydberg-formula", "balmer-series-limit", "spectral-analysis", "stellar-spectroscopy"], "payload": {"question_id": "cuet-phy-atom-bohr-20", "subtopic": "Bohr Model of Hydrogen Atom", "topic_name": "Bohr Model of Hydrogen Atom", "bloom_level": "evaluate", "options": [{"key": "A", "text": "656.3 nm, visible region", "is_correct": false}, {"key": "B", "text": "121.5 nm, ultraviolet region", "is_correct": false}, {"key": "C", "text": "820.4 nm, infrared region", "is_correct": false}, {"key": "D", "text": "364.6 nm, ultraviolet region", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "656.3 nm is the wavelength of the first Balmer line (Hα, n = 3 to n = 2), not the series limit. The series limit has the shortest wavelength in the series.", "misconception": "Confusing the first line of the Balmer series with the series limit"}, {"option_key": "B", "hint": "121.5 nm corresponds to the Lyman-α line (n = 2 to n = 1), not the Balmer series limit. This is in the far UV.", "misconception": "Confusing Lyman series transitions with Balmer series limit"}, {"option_key": "C", "hint": "820.4 nm lies in the infrared region. The Balmer series lies in the visible-to-near-UV region, with the series limit at 364.6 nm.", "misconception": "Using an incorrect formula or confusing with the Paschen series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The Lyman series of hydrogen spectrum lies in the:", "explanation": "The Lyman series corresponds to transitions from higher energy levels (n = 2, 3, 4, ...) to n = 1 (ground state). The wavelengths of the Lyman series range from 912 A to 1216 A, which fall in the ultraviolet (UV) region of the electromagnetic spectrum.", "correct_answer": "A", "concept_tags": ["lyman-series", "ultraviolet-region", "hydrogen-spectrum"], "payload": {"question_id": "cuet-phy-atom-spectra-01", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "Ultraviolet region", "is_correct": true}, {"key": "B", "text": "Visible region", "is_correct": false}, {"key": "C", "text": "Infrared region", "is_correct": false}, {"key": "D", "text": "Microwave region", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The visible region corresponds to the Balmer series (transitions to n = 2), not the Lyman series.", "misconception": "Confusing Balmer and Lyman series regions"}, {"option_key": "C", "hint": "The infrared region corresponds to the Paschen, Brackett, and Pfund series, not the Lyman series.", "misconception": "Confusing Paschen and Lyman series regions"}, {"option_key": "D", "hint": "Microwave wavelengths are much longer than the Lyman series wavelengths. No hydrogen spectral series falls in the microwave region.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The ratio of the maximum wavelength to the minimum wavelength of the Balmer series of hydrogen is:", "explanation": "The maximum wavelength of the Balmer series corresponds to the first line (n = 3 to n = 2): 1/lambda_max = R(1/4 - 1/9) = R(5/36), so lambda_max = 36/(5R). The minimum wavelength (series limit) corresponds to n = infinity to n = 2: 1/lambda_min = R(1/4 - 0) = R/4, so lambda_min = 4/R. Ratio = lambda_max/lambda_min = (36/5R)/(4/R) = 36/(5 x 4) = 36/20 = 9/5.", "correct_answer": "C", "concept_tags": ["balmer-series", "wavelength-ratio", "series-limit", "first-line", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-02", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "4/3", "is_correct": false}, {"key": "B", "text": "5/4", "is_correct": false}, {"key": "C", "text": "9/5", "is_correct": true}, {"key": "D", "text": "27/5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4/3 is the ratio of quantum numbers (n = 4 to n = 3), not the ratio of wavelengths. The calculation requires the full Rydberg formula.", "misconception": "Using ratio of quantum numbers instead of the Rydberg formula"}, {"option_key": "B", "hint": "5/4 does not arise from any correct combination of the Rydberg terms for the Balmer series.", "misconception": null}, {"option_key": "D", "hint": "27/5 would result from an incorrect calculation. The correct ratio is lambda_max/lambda_min = (36/5R)/(4/R) = 9/5.", "misconception": "Arithmetic error in simplifying the ratio"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The first line of the Balmer series of hydrogen corresponds to the transition:", "explanation": "The Balmer series corresponds to transitions from higher levels to n = 2. The first line (longest wavelength, lowest energy) corresponds to the transition from the nearest higher level, i.e., n = 3 to n = 2. This line is called H-alpha and has a wavelength of 6563 A (red colour).", "correct_answer": "B", "concept_tags": ["balmer-series", "first-line", "h-alpha", "hydrogen-transitions"], "payload": {"question_id": "cuet-phy-atom-spectra-03", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "n = 2 to n = 1", "is_correct": false}, {"key": "B", "text": "n = 3 to n = 2", "is_correct": true}, {"key": "C", "text": "n = infinity to n = 2", "is_correct": false}, {"key": "D", "text": "n = 4 to n = 2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The transition from n = 2 to n = 1 belongs to the Lyman series, not the Balmer series.", "misconception": "Confusing Lyman and Balmer series"}, {"option_key": "C", "hint": "The transition from n = infinity to n = 2 gives the series limit (shortest wavelength), not the first line of the Balmer series.", "misconception": "Confusing series limit with the first line"}, {"option_key": "D", "hint": "The transition from n = 4 to n = 2 gives the second line (H-beta) of the Balmer series, not the first line.", "misconception": "Incorrect ordering of spectral lines"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The energy of the hydrogen atom in the ground state is -13.6 eV. The energy of the hydrogen atom in the second excited state is:", "explanation": "The energy of the hydrogen atom in the nth level is given by E_n = -13.6/n^2 eV. The second excited state corresponds to n = 3 (ground state is n = 1, first excited state is n = 2, second excited state is n = 3). So E_3 = -13.6/3^2 = -13.6/9 = -1.51 eV.", "correct_answer": "D", "concept_tags": ["energy-levels", "hydrogen-atom", "second-excited-state"], "payload": {"question_id": "cuet-phy-atom-spectra-04", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "-13.6 eV", "is_correct": false}, {"key": "B", "text": "-3.4 eV", "is_correct": false}, {"key": "C", "text": "-0.85 eV", "is_correct": false}, {"key": "D", "text": "-1.51 eV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "-13.6 eV is the ground state energy (n = 1), not the second excited state.", "misconception": null}, {"option_key": "B", "hint": "-3.4 eV corresponds to n = 2 (first excited state). The second excited state is n = 3, not n = 2.", "misconception": "Confusing first excited state with second excited state"}, {"option_key": "C", "hint": "-0.85 eV corresponds to n = 4 (third excited state). Remember: second excited state means n = 3.", "misconception": "Incorrect identification of quantum number for excited states"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Lyman series of hydrogen is 1216 A. The wavelength of the second line of the Balmer series is:", "explanation": "For the first line of the Lyman series (n = 2 to n = 1): 1/lambda_L = R(1/1^2 - 1/2^2) = R(1 - 1/4) = 3R/4. So lambda_L = 4/(3R). For the second line of the Balmer series (n = 4 to n = 2): 1/lambda_B = R(1/2^2 - 1/4^2) = R(1/4 - 1/16) = R(3/16) = 3R/16. So lambda_B = 16/(3R). Taking the ratio: lambda_B/lambda_L = (16/3R)/(4/3R) = 16/4 = 4. Therefore lambda_B = 4 x 1216 = 4864 A.", "correct_answer": "B", "concept_tags": ["lyman-series", "balmer-series", "wavelength-ratio", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-05", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "3648 A", "is_correct": false}, {"key": "B", "text": "4864 A", "is_correct": true}, {"key": "C", "text": "6568 A", "is_correct": false}, {"key": "D", "text": "1216 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3648 A would correspond to a ratio of 3, but the correct wavelength ratio between the second Balmer line and the first Lyman line is 4.", "misconception": "Incorrect application of the Rydberg formula"}, {"option_key": "C", "hint": "6568 A is close to the first line of the Balmer series (H-alpha), not the second line.", "misconception": "Confusing first and second lines of Balmer series"}, {"option_key": "D", "hint": "1216 A is the given wavelength of the first Lyman line. The Balmer series lines have longer wavelengths since they involve lower energy transitions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the shortest wavelength of the Balmer series to the shortest wavelength of the Lyman series of hydrogen is:", "explanation": "The shortest wavelength (series limit) of any series corresponds to the transition from n = infinity. For the Lyman series limit: 1/lambda_L = R(1/1^2 - 0) = R, so lambda_L = 1/R. For the Balmer series limit: 1/lambda_B = R(1/2^2 - 0) = R/4, so lambda_B = 4/R. Ratio = lambda_B/lambda_L = (4/R)/(1/R) = 4.", "correct_answer": "C", "concept_tags": ["series-limit", "balmer-series", "lyman-series", "wavelength-ratio"], "payload": {"question_id": "cuet-phy-atom-spectra-06", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "2", "is_correct": false}, {"key": "C", "text": "4", "is_correct": true}, {"key": "D", "text": "1/4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A ratio of 1 would mean both series have the same shortest wavelength, which is incorrect since the Balmer series transitions involve less energy.", "misconception": null}, {"option_key": "B", "hint": "A ratio of 2 would correspond to the ratio of the quantum numbers, but the wavelength depends on 1/n^2, giving a ratio of n^2 = 2^2 = 4.", "misconception": "Using n instead of n^2 in the formula"}, {"option_key": "D", "hint": "1/4 would mean the Balmer series limit has a shorter wavelength than the Lyman series limit, which contradicts the fact that Lyman series photons have higher energy.", "misconception": "Inverting the ratio"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The excitation energy required to excite a hydrogen atom from the ground state to the first excited state is:", "explanation": "The excitation energy is the difference between the energy of the excited state and the ground state. E_1 = -13.6 eV (ground state, n = 1). E_2 = -13.6/4 = -3.4 eV (first excited state, n = 2). Excitation energy = E_2 - E_1 = -3.4 - (-13.6) = -3.4 + 13.6 = 10.2 eV.", "correct_answer": "A", "concept_tags": ["excitation-energy", "ground-state", "first-excited-state", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-07", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "10.2 eV", "is_correct": true}, {"key": "B", "text": "13.6 eV", "is_correct": false}, {"key": "C", "text": "3.4 eV", "is_correct": false}, {"key": "D", "text": "1.89 eV", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "13.6 eV is the ionization energy from the ground state (energy needed to completely remove the electron), not the excitation energy to the first excited state.", "misconception": "Confusing ionization energy with excitation energy"}, {"option_key": "C", "hint": "3.4 eV is the magnitude of the energy of the first excited state, not the energy required to reach it from the ground state.", "misconception": "Confusing energy of a state with the excitation energy"}, {"option_key": "D", "hint": "1.89 eV is the energy difference between n = 3 and n = 2 (corresponding to the first Balmer line), not the excitation energy from the ground state.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ionization energy of the hydrogen atom from its second excited state is:", "explanation": "The second excited state corresponds to n = 3. The energy of this state is E_3 = -13.6/3^2 = -13.6/9 = -1.51 eV. The ionization energy is the energy required to remove the electron from this state to n = infinity (E = 0). So ionization energy = 0 - (-1.51) = 1.51 eV.", "correct_answer": "D", "concept_tags": ["ionization-energy", "second-excited-state", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-08", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 eV", "is_correct": false}, {"key": "B", "text": "3.4 eV", "is_correct": false}, {"key": "C", "text": "0.85 eV", "is_correct": false}, {"key": "D", "text": "1.51 eV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "13.6 eV is the ionization energy from the ground state (n = 1), not from the second excited state (n = 3).", "misconception": "Not adjusting ionization energy for the starting level"}, {"option_key": "B", "hint": "3.4 eV is the ionization energy from the first excited state (n = 2), not the second excited state (n = 3).", "misconception": "Confusing first and second excited states"}, {"option_key": "C", "hint": "0.85 eV is the ionization energy from n = 4 (third excited state), not n = 3 (second excited state).", "misconception": "Using wrong quantum number for the second excited state"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The wavelength of the first line of the Lyman series of a hydrogen-like ion He+ is:", "explanation": "For hydrogen-like ions, 1/lambda = RZ^2(1/n1^2 - 1/n2^2). For the first line of the Lyman series of He+ (Z = 2): 1/lambda = R(2)^2(1/1^2 - 1/2^2) = 4R(3/4) = 3R. For hydrogen, the first Lyman line: 1/lambda_H = R(3/4), so lambda_H = 4/(3R). For He+: 1/lambda_He = 3R, so lambda_He = 1/(3R). Ratio: lambda_He/lambda_H = (1/3R)/(4/3R) = 1/4. Since lambda_H = 1216 A, lambda_He = 1216/4 = 304 A.", "correct_answer": "A", "concept_tags": ["hydrogen-like-ions", "helium-ion", "lyman-series", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-09", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "304 A", "is_correct": true}, {"key": "B", "text": "608 A", "is_correct": false}, {"key": "C", "text": "1216 A", "is_correct": false}, {"key": "D", "text": "152 A", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "608 A would result from dividing the hydrogen wavelength by 2 (using Z instead of Z^2). The correct formula uses Z^2 = 4 as the scaling factor.", "misconception": "Using Z instead of Z^2 in the Rydberg formula for hydrogen-like ions"}, {"option_key": "C", "hint": "1216 A is the first Lyman line of hydrogen (Z = 1). For He+ (Z = 2), the wavelength is scaled down by Z^2 = 4.", "misconception": "Ignoring the Z^2 factor for hydrogen-like ions"}, {"option_key": "D", "hint": "152 A would result from dividing by Z^3 = 8 instead of Z^2 = 4.", "misconception": "Using incorrect power of Z"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The wavelength of the first line of the Balmer series of hydrogen is 6563 A. The wavelength of the first line of the Lyman series of the same atom is approximately:", "explanation": "For the first Balmer line (n = 3 to n = 2): 1/lambda_B = R(1/4 - 1/9) = R(5/36). For the first Lyman line (n = 2 to n = 1): 1/lambda_L = R(1 - 1/4) = R(3/4). Ratio: lambda_L/lambda_B = (5/36)/(3/4) = (5/36) x (4/3) = 20/108 = 5/27. Therefore lambda_L = (5/27) x 6563 = 32815/27 = 1215.4 A, which is approximately 1215 A.", "correct_answer": "B", "concept_tags": ["balmer-series", "lyman-series", "wavelength-ratio", "rydberg-formula"], "payload": {"question_id": "cuet-phy-atom-spectra-10", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "912 A", "is_correct": false}, {"key": "B", "text": "1215 A", "is_correct": true}, {"key": "C", "text": "1640 A", "is_correct": false}, {"key": "D", "text": "3282 A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "912 A is the series limit (shortest wavelength) of the Lyman series, not the first line.", "misconception": "Confusing the series limit with the first spectral line"}, {"option_key": "C", "hint": "This value does not correspond to any standard hydrogen spectral line. Check the ratio calculation using the Rydberg formula.", "misconception": null}, {"option_key": "D", "hint": "3282 A would be half of 6563, suggesting a simple halving, but the relationship between spectral lines requires the full Rydberg formula.", "misconception": "Assuming a simple integer ratio between different series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A hydrogen atom in the ground state absorbs a photon of energy 12.75 eV. The number of different spectral lines that can be emitted when the atom returns to the ground state is:", "explanation": "The energy of the ground state is -13.6 eV. After absorbing 12.75 eV, the total energy becomes -13.6 + 12.75 = -0.85 eV. Using E_n = -13.6/n^2: -0.85 = -13.6/n^2, so n^2 = 13.6/0.85 = 16, giving n = 4. The atom is excited to n = 4. The number of possible spectral lines emitted when it de-excites is n(n-1)/2 = 4(3)/2 = 6.", "correct_answer": "C", "concept_tags": ["photon-absorption", "energy-levels", "spectral-lines-formula", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-11", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "3", "is_correct": false}, {"key": "C", "text": "6", "is_correct": true}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 line would mean only a direct transition from the excited state to the ground state. But the atom can also de-excite through intermediate levels.", "misconception": "Considering only direct transitions to the ground state"}, {"option_key": "B", "hint": "3 would be the number of direct transitions from n = 4 (to n = 3, 2, 1), but transitions between intermediate levels (3->2, 3->1, 2->1) must also be counted.", "misconception": "Counting only transitions from the highest excited level"}, {"option_key": "D", "hint": "10 corresponds to n = 5 using the formula n(n-1)/2. First verify that the absorbed energy takes the atom to n = 4, not n = 5.", "misconception": "Incorrect calculation of the excited state quantum number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following transitions in the hydrogen atom will emit a photon of the highest frequency?", "explanation": "The frequency of the emitted photon is proportional to the energy difference between the two levels. E_n = -13.6/n^2 eV. For n = 2 to n = 1: Delta E = -13.6(1/1 - 1/4) = -13.6 x 3/4 = 10.2 eV. For n = 6 to n = 5: Delta E = -13.6(1/25 - 1/36) = -13.6 x 11/900 = 0.166 eV. For n = 4 to n = 3: Delta E = -13.6(1/9 - 1/16) = -13.6 x 7/144 = 0.66 eV. For n = 3 to n = 2: Delta E = -13.6(1/4 - 1/9) = -13.6 x 5/36 = 1.89 eV. The transition n = 2 to n = 1 has the largest energy difference and hence the highest frequency.", "correct_answer": "D", "concept_tags": ["transition-energy", "photon-frequency", "energy-level-diagram"], "payload": {"question_id": "cuet-phy-atom-spectra-12", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "n = 6 to n = 5", "is_correct": false}, {"key": "B", "text": "n = 4 to n = 3", "is_correct": false}, {"key": "C", "text": "n = 3 to n = 2", "is_correct": false}, {"key": "D", "text": "n = 2 to n = 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The energy gap between n = 6 and n = 5 is very small (about 0.17 eV) as higher energy levels are closely spaced.", "misconception": "Assuming higher quantum numbers give higher energy transitions"}, {"option_key": "B", "hint": "The n = 4 to n = 3 transition releases only 0.66 eV, much less than n = 2 to n = 1 which releases 10.2 eV.", "misconception": null}, {"option_key": "C", "hint": "While n = 3 to n = 2 gives 1.89 eV, the n = 2 to n = 1 transition gives 10.2 eV, which is much larger.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The Balmer series of hydrogen spectrum is the only series that has some lines in the visible region. Reason (R): The wavelengths of the Balmer series range from 3646 A to 6563 A, which partially overlaps with the visible spectrum (3800 A to 7800 A).", "explanation": "The assertion is correct. Among all hydrogen spectral series, only the Balmer series has wavelengths in the visible range. The Lyman series is entirely in the UV region, while the Paschen, Brackett, and Pfund series are all in the infrared region. The reason is also correct and correctly explains the assertion. The Balmer series wavelengths (3646 A to 6563 A) do overlap with the visible range, which is why some Balmer lines (like H-alpha at 6563 A, H-beta at 4861 A) are visible to the human eye.", "correct_answer": "A", "concept_tags": ["balmer-series", "visible-spectrum", "hydrogen-spectral-series"], "payload": {"question_id": "cuet-phy-atom-spectra-13", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why Balmer lines are visible — their wavelength range overlaps with the visible spectrum. So R is indeed the correct explanation of A.", "misconception": "Failing to see the causal connection between the wavelength range and visibility"}, {"option_key": "C", "hint": "The reason provides accurate wavelength data for the Balmer series. The range 3646 A to 6563 A is correct (series limit to first line).", "misconception": null}, {"option_key": "D", "hint": "The assertion is correct — no other hydrogen series (Lyman, Paschen, etc.) falls in the visible range.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The spectral lines of the Lyman series of hydrogen have shorter wavelengths than those of the Balmer series. Reason (R): In the Franck-Hertz experiment, electrons lose energy in discrete amounts when they collide with mercury atoms, confirming the existence of quantized energy levels.", "explanation": "The assertion is correct. The Lyman series (transitions to n = 1) involves larger energy differences than the Balmer series (transitions to n = 2), so Lyman series photons have higher energy and shorter wavelength. The reason is also correct — the Franck-Hertz experiment does confirm quantized energy levels. However, the reason is NOT the correct explanation of the assertion. The shorter wavelengths of the Lyman series are due to the larger energy gaps when transitioning to n = 1, not because of the Franck-Hertz experiment.", "correct_answer": "B", "concept_tags": ["lyman-series", "balmer-series", "franck-hertz-experiment", "quantized-energy-levels"], "payload": {"question_id": "cuet-phy-atom-spectra-14", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are independently correct, the Franck-Hertz experiment explains quantized energy levels in general — it does not specifically explain why the Lyman series has shorter wavelengths than the Balmer series.", "misconception": "Assuming any correct physics statement about energy levels is the explanation for spectral wavelength differences"}, {"option_key": "C", "hint": "The reason is correct — the Franck-Hertz experiment is a well-known experiment that demonstrated quantized energy levels in atoms.", "misconception": "Not recognizing the Franck-Hertz experiment as a valid confirmation of energy quantization"}, {"option_key": "D", "hint": "The assertion is correct — Lyman series wavelengths (912-1216 A) are indeed shorter than Balmer series wavelengths (3646-6563 A).", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the spectral series in Column I with the spectral region in Column II:\n\nColumn I:\nA. Lyman series\nB. Balmer series\nC. Paschen series\nD. Brackett series\n\nColumn II:\n1. Visible and near UV\n2. Ultraviolet\n3. Far infrared\n4. Near infrared", "explanation": "The Lyman series (transitions to n = 1) lies in the ultraviolet region (A-2). The Balmer series (transitions to n = 2) lies in the visible and near UV region (B-1). The Paschen series (transitions to n = 3) lies in the near infrared region (C-4). The Brackett series (transitions to n = 4) lies in the far infrared region (D-3).", "correct_answer": "D", "concept_tags": ["lyman-series", "balmer-series", "paschen-series", "brackett-series", "spectral-regions"], "payload": {"question_id": "cuet-phy-atom-spectra-15", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "A-2, B-1, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-1, D-3", "is_correct": false}, {"key": "C", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-2, B-1, C-4, D-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This swaps C and D. Paschen series lies in the near infrared (C-4), and Brackett series lies in the far infrared (D-3), not the other way around.", "misconception": "Swapping Paschen and Brackett series spectral regions"}, {"option_key": "B", "hint": "This assigns the Balmer series to infrared, which is incorrect. The Balmer series falls in the visible/near UV region.", "misconception": "Incorrectly placing the Balmer series in the infrared region"}, {"option_key": "C", "hint": "This swaps A and B. The Lyman series is in the UV region (A-2), and the Balmer series is in the visible region (B-1).", "misconception": "Confusing Lyman and Balmer series regions"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the transitions in Column I with their spectral series in Column II:\n\nColumn I:\nA. n = 5 to n = 2\nB. n = 4 to n = 1\nC. n = 7 to n = 3\nD. n = 6 to n = 4\n\nColumn II:\n1. Lyman series\n2. Balmer series\n3. Paschen series\n4. Brackett series", "explanation": "A spectral line belongs to a series determined by its lower energy level. n = 5 to n = 2: lower level is n = 2, so it belongs to the Balmer series (A-2). n = 4 to n = 1: lower level is n = 1, so it belongs to the Lyman series (B-1). n = 7 to n = 3: lower level is n = 3, so it belongs to the Paschen series (C-3). n = 6 to n = 4: lower level is n = 4, so it belongs to the Brackett series (D-4).", "correct_answer": "C", "concept_tags": ["spectral-series-identification", "electron-transitions", "lyman-balmer-paschen-brackett"], "payload": {"question_id": "cuet-phy-atom-spectra-16", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-1, B-2, C-3, D-4", "is_correct": false}, {"key": "B", "text": "A-2, B-1, C-4, D-3", "is_correct": false}, {"key": "C", "text": "A-2, B-1, C-3, D-4", "is_correct": true}, {"key": "D", "text": "A-3, B-1, C-2, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns A to the Lyman series. The transition n = 5 to n = 2 has a lower level of n = 2, which corresponds to the Balmer series, not Lyman.", "misconception": "Identifying the series by the upper quantum number instead of the lower one"}, {"option_key": "B", "hint": "This swaps C and D. The transition n = 7 to n = 3 ends at n = 3 (Paschen), and n = 6 to n = 4 ends at n = 4 (Brackett).", "misconception": "Confusing Paschen and Brackett series"}, {"option_key": "D", "hint": "This assigns A to Paschen (n = 3), but the transition n = 5 to n = 2 ends at n = 2, making it a Balmer series line.", "misconception": "Incorrectly identifying the lower quantum number of the transition"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The series limit (shortest wavelength) of the Lyman series of hydrogen corresponds to the ionization energy of 13.6 eV from the ground state.", "explanation": "This statement is true. The series limit of the Lyman series corresponds to the transition from n = infinity to n = 1. The energy of this photon is E = E_infinity - E_1 = 0 - (-13.6) = 13.6 eV, which is exactly the ionization energy of hydrogen from the ground state. The corresponding wavelength is 912 A.", "correct_answer": "A", "concept_tags": ["series-limit", "lyman-series", "ionization-energy", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-17", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The series limit of the Lyman series is the transition from n = infinity to n = 1, which releases exactly 13.6 eV — the ionization energy. The statement is true.", "misconception": "Not recognizing that the Lyman series limit equals the ionization energy from the ground state"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The Paschen series of hydrogen spectrum lies in the visible region of the electromagnetic spectrum.", "explanation": "This statement is false. The Paschen series corresponds to transitions from higher energy levels to n = 3. The wavelengths of the Paschen series range from approximately 8204 A to 18750 A, which fall entirely in the infrared region of the electromagnetic spectrum, not the visible region (3800 A to 7800 A). Only the Balmer series has lines in the visible region.", "correct_answer": "B", "concept_tags": ["paschen-series", "infrared-region", "hydrogen-spectrum"], "payload": {"question_id": "cuet-phy-atom-spectra-18", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The Paschen series (transitions to n = 3) has wavelengths in the range 8204 A to 18750 A, which lies entirely in the infrared, not the visible region.", "misconception": "Confusing the spectral region of the Paschen series with the Balmer series"}, {"option_key": "C", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}, {"option_key": "D", "hint": "This is a placeholder option and not a valid choice.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The excitation potential required to excite a hydrogen atom from the ground state to the first excited state is _____ V.", "explanation": "The excitation energy from the ground state (n = 1) to the first excited state (n = 2) is: Delta E = E_2 - E_1 = (-13.6/4) - (-13.6) = -3.4 + 13.6 = 10.2 eV. The excitation potential is the potential difference through which an electron must be accelerated to gain this energy. Since the energy is 10.2 eV, the excitation potential is 10.2 V (because eV = eV, so V = 10.2 V).", "correct_answer": "C", "concept_tags": ["excitation-potential", "ground-state", "first-excited-state", "hydrogen-atom"], "payload": {"question_id": "cuet-phy-atom-spectra-19", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "13.6 V", "is_correct": false}, {"key": "B", "text": "3.4 V", "is_correct": false}, {"key": "C", "text": "10.2 V", "is_correct": true}, {"key": "D", "text": "12.1 V", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "13.6 V is the ionization potential from the ground state, not the excitation potential to the first excited state.", "misconception": "Confusing ionization potential with excitation potential"}, {"option_key": "B", "hint": "3.4 V corresponds to the magnitude of the energy of the first excited state (-3.4 eV), not the energy difference from the ground state.", "misconception": "Using the energy of the final state instead of the energy difference"}, {"option_key": "D", "hint": "12.1 V is the excitation potential to the third energy level (n = 3), not the first excited state (n = 2). E_3 - E_1 = -1.51 + 13.6 = 12.09 eV.", "misconception": "Confusing the second excited state with the first excited state"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-atom-spectra", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a laboratory, a student is studying the emission spectrum of hydrogen gas using a discharge tube. The student observes that when the gas is excited, electrons jump to higher energy levels and then fall back, emitting radiation. The student records that the electron transitions from the 5th energy level produce spectral lines belonging to different series.\n\nHow many spectral lines in the Balmer series can be produced from transitions originating at the 5th energy level?", "explanation": "The Balmer series consists of transitions where the lower energy level is n = 2. From the 5th energy level, the possible transitions to n = 2 are: 5->2, 4->2, and 3->2. However, the question asks specifically for lines originating from transitions that start at n = 5. The direct transitions from n = 5 that belong to the Balmer series is only 5->2 (one line). But electrons from n = 5 can also cascade: 5->4->2, 5->3->2, etc. The Balmer series lines that can appear when electrons de-excite from n = 5 are: 5->2, 4->2, and 3->2. That gives 3 lines in the Balmer series. These are the transitions ending at n = 2 from levels 3, 4, and 5.", "correct_answer": "B", "concept_tags": ["balmer-series", "spectral-lines", "electron-transitions", "emission-spectrum"], "payload": {"question_id": "cuet-phy-atom-spectra-20", "subtopic": "Hydrogen Spectrum and Spectral Series", "topic_name": "Hydrogen Spectrum and Spectral Series", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "3", "is_correct": true}, {"key": "C", "text": "6", "is_correct": false}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 would be the count if only the direct transition 5->2 is considered. But through cascading, intermediate levels (n = 3, 4) also emit Balmer lines when they transition to n = 2.", "misconception": "Counting only the direct transition from n = 5 to n = 2"}, {"option_key": "C", "hint": "6 is the total number of spectral lines from all series when an electron de-excites from n = 4 using n(n-1)/2. This question asks only about Balmer series lines from n = 5.", "misconception": "Calculating total spectral lines instead of just Balmer series lines"}, {"option_key": "D", "hint": "10 is the total number of spectral lines from all series when an electron de-excites from n = 5. The question asks only about Balmer series lines.", "misconception": "Using n(n-1)/2 formula without restricting to Balmer series"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In alpha decay, the parent nucleus emits:", "explanation": "In alpha decay, the parent nucleus emits an alpha particle, which is a helium-4 nucleus (₂He⁴) consisting of 2 protons and 2 neutrons. As a result, the mass number A decreases by 4 and the atomic number Z decreases by 2. For example, ²³⁸U → ²³⁴Th + ⁴He.", "correct_answer": "A", "concept_tags": ["alpha-decay", "helium-nucleus", "mass-number", "atomic-number"], "payload": {"question_id": "cuet-phy-nuclei-decay-01", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "A helium nucleus (₂He⁴) with A decreasing by 4 and Z by 2", "is_correct": true}, {"key": "B", "text": "An electron and an antineutrino", "is_correct": false}, {"key": "C", "text": "A high-energy photon with no change in A or Z", "is_correct": false}, {"key": "D", "text": "A proton with A decreasing by 1 and Z by 1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Emission of an electron and antineutrino describes beta-minus (β⁻) decay, not alpha decay.", "misconception": "Confusing alpha decay with beta-minus decay"}, {"option_key": "C", "hint": "Emission of a high-energy photon with no change in A or Z describes gamma decay, not alpha decay.", "misconception": "Confusing alpha decay with gamma decay"}, {"option_key": "D", "hint": "Proton emission is a rare decay mode. Alpha decay specifically involves emission of ₂He⁴, not a single proton.", "misconception": "Confusing alpha particle with a proton"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of radioactive activity is:", "explanation": "The SI unit of radioactive activity (rate of disintegration) is the becquerel (Bq), where 1 Bq = 1 disintegration per second. The older unit curie (Ci) is defined as 1 Ci = 3.7 × 10¹⁰ disintegrations per second, which was originally based on the activity of 1 gram of Ra-226.", "correct_answer": "B", "concept_tags": ["activity", "becquerel", "curie", "SI-units"], "payload": {"question_id": "cuet-phy-nuclei-decay-02", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "Curie (Ci)", "is_correct": false}, {"key": "B", "text": "Becquerel (Bq)", "is_correct": true}, {"key": "C", "text": "Rutherford (Rd)", "is_correct": false}, {"key": "D", "text": "Gray (Gy)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Curie is a non-SI (older CGS) unit of activity. The SI unit is becquerel. 1 Ci = 3.7 × 10¹⁰ Bq.", "misconception": "Confusing SI unit with the older traditional unit of activity"}, {"option_key": "C", "hint": "Rutherford (1 Rd = 10⁶ disintegrations/s) is another non-SI unit and is rarely used in modern physics.", "misconception": "Confusing the rutherford unit with the SI unit"}, {"option_key": "D", "hint": "Gray (Gy) is the SI unit of absorbed radiation dose (energy per unit mass), not activity.", "misconception": "Confusing activity with absorbed dose"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The half-life of a radioactive substance is 20 minutes. The fraction of the original sample that remains after 1 hour is:", "explanation": "In 1 hour = 60 minutes, the number of half-lives n = 60/20 = 3. After n half-lives, the fraction remaining is (1/2)ⁿ = (1/2)³ = 1/8. So 1/8 of the original sample remains undecayed after 1 hour.", "correct_answer": "C", "concept_tags": ["half-life", "radioactive-decay", "fraction-remaining"], "payload": {"question_id": "cuet-phy-nuclei-decay-03", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "1/2", "is_correct": false}, {"key": "B", "text": "1/4", "is_correct": false}, {"key": "C", "text": "1/8", "is_correct": true}, {"key": "D", "text": "1/16", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1/2 would remain after just one half-life (20 min), not after 60 min. Count the number of half-lives: 60/20 = 3.", "misconception": "Using only one half-life period instead of calculating the correct number"}, {"option_key": "B", "hint": "1/4 would remain after two half-lives (40 min). After 60 min, three half-lives have elapsed, giving (1/2)³ = 1/8.", "misconception": "Miscounting the number of half-lives"}, {"option_key": "D", "hint": "1/16 = (1/2)⁴ would require four half-lives (80 min), but only 60 min have elapsed (3 half-lives).", "misconception": "Incorrectly calculating the number of half-lives"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In gamma decay, the emitted radiation is:", "explanation": "Gamma decay involves the emission of high-energy electromagnetic radiation (photons) from a nucleus in an excited state transitioning to a lower energy state. During gamma emission, there is no change in the mass number (A) or atomic number (Z) of the nucleus, as no nucleons are emitted or converted.", "correct_answer": "D", "concept_tags": ["gamma-decay", "electromagnetic-radiation", "isomeric-transition"], "payload": {"question_id": "cuet-phy-nuclei-decay-04", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "A stream of electrons", "is_correct": false}, {"key": "B", "text": "A stream of helium nuclei", "is_correct": false}, {"key": "C", "text": "A stream of neutrons", "is_correct": false}, {"key": "D", "text": "High-energy electromagnetic radiation (photons)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Electrons are emitted in beta-minus (β⁻) decay, not gamma decay. Gamma rays are electromagnetic radiation.", "misconception": "Confusing gamma radiation with beta radiation"}, {"option_key": "B", "hint": "Helium nuclei are emitted in alpha decay, not gamma decay.", "misconception": "Confusing gamma decay with alpha decay"}, {"option_key": "C", "hint": "Neutrons are not emitted in gamma decay. Gamma decay involves no particle emission, only photon emission.", "misconception": "Confusing gamma emission with neutron emission"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The half-life of a radioactive element is T₁/₂. The mean life (τ) of the element is:", "explanation": "The decay constant λ = 0.693/T₁/₂. The mean life is τ = 1/λ = T₁/₂/0.693 = T₁/₂/ln2 ≈ 1.44 T₁/₂. The mean life is always greater than the half-life by a factor of 1/ln2 ≈ 1.44.", "correct_answer": "B", "concept_tags": ["mean-life", "half-life", "decay-constant", "relation"], "payload": {"question_id": "cuet-phy-nuclei-decay-05", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "0.693 T₁/₂", "is_correct": false}, {"key": "B", "text": "T₁/₂ / 0.693", "is_correct": true}, {"key": "C", "text": "T₁/₂ / 2", "is_correct": false}, {"key": "D", "text": "2 T₁/₂", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.693 T₁/₂ gives a value less than T₁/₂, but the mean life is always greater than the half-life. The relation is τ = T₁/₂ / 0.693.", "misconception": "Inverting the relation between mean life and half-life"}, {"option_key": "C", "hint": "T₁/₂/2 has no physical basis. The correct relation involves the natural logarithm of 2, i.e., τ = T₁/₂/ln2.", "misconception": "Guessing an arbitrary simple fraction"}, {"option_key": "D", "hint": "2T₁/₂ is incorrect. The correct factor is 1/ln2 ≈ 1.44, not 2.", "misconception": "Approximating 1/ln2 as 2 instead of the correct value 1.44"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A radioactive sample has an initial activity of 800 Bq. If the half-life is 4 hours, the activity after 12 hours will be:", "explanation": "Number of half-lives = 12/4 = 3. Activity after n half-lives: A = A₀(1/2)ⁿ = 800 × (1/2)³ = 800 × 1/8 = 100 Bq. Activity decays exponentially just like the number of undecayed nuclei.", "correct_answer": "C", "concept_tags": ["activity", "half-life", "exponential-decay", "becquerel"], "payload": {"question_id": "cuet-phy-nuclei-decay-06", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "400 Bq", "is_correct": false}, {"key": "B", "text": "200 Bq", "is_correct": false}, {"key": "C", "text": "100 Bq", "is_correct": true}, {"key": "D", "text": "50 Bq", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "400 Bq = 800/2 is the activity after only 1 half-life (4 hours), not 12 hours.", "misconception": "Using only one half-life instead of calculating the correct number"}, {"option_key": "B", "hint": "200 Bq = 800/4 is the activity after 2 half-lives (8 hours), not 12 hours.", "misconception": "Miscounting the number of half-lives as 2 instead of 3"}, {"option_key": "D", "hint": "50 Bq = 800/16 would require 4 half-lives (16 hours), but only 12 hours have passed.", "misconception": "Overcounting the number of half-lives"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In β⁻ decay, a neutron inside the nucleus is converted into:", "explanation": "In beta-minus (β⁻) decay, a neutron inside the nucleus transforms into a proton, an electron (β⁻ particle), and an antineutrino: n → p + e⁻ + ν̄ₑ. The atomic number Z increases by 1 while the mass number A remains unchanged. The antineutrino carries away part of the energy, which explains the continuous energy spectrum of β⁻ particles.", "correct_answer": "A", "concept_tags": ["beta-minus-decay", "neutron-conversion", "antineutrino", "atomic-number"], "payload": {"question_id": "cuet-phy-nuclei-decay-07", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "A proton, an electron, and an antineutrino", "is_correct": true}, {"key": "B", "text": "A proton, an electron, and a neutrino", "is_correct": false}, {"key": "C", "text": "A proton, a positron, and a neutrino", "is_correct": false}, {"key": "D", "text": "A proton and an electron only", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In β⁻ decay, the emitted lepton partner is an antineutrino (ν̄ₑ), not a neutrino. A neutrino is emitted in β⁺ decay.", "misconception": "Confusing neutrino with antineutrino in beta-minus decay"}, {"option_key": "C", "hint": "Positron emission occurs in β⁺ decay (p → n + e⁺ + νₑ), not in β⁻ decay.", "misconception": "Confusing beta-minus decay with beta-plus decay"}, {"option_key": "D", "hint": "A third particle (antineutrino) is essential to conserve energy, momentum, and lepton number. Its existence was postulated by Pauli to explain the continuous β-spectrum.", "misconception": "Ignoring the role of the antineutrino in beta decay"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In the nuclear fission of ²³⁵U by a slow neutron, the approximate energy released per fission is:", "explanation": "The fission of one ²³⁵U nucleus by a thermal (slow) neutron releases approximately 200 MeV of energy. This energy appears as kinetic energy of fission fragments (~165 MeV), kinetic energy of neutrons (~5 MeV), prompt gamma rays (~7 MeV), energy of fission products'' beta and gamma decay (~23 MeV), and neutrino energy (~12 MeV).", "correct_answer": "D", "concept_tags": ["nuclear-fission", "uranium-235", "energy-release", "slow-neutron"], "payload": {"question_id": "cuet-phy-nuclei-decay-08", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "2 MeV", "is_correct": false}, {"key": "B", "text": "20 MeV", "is_correct": false}, {"key": "C", "text": "2000 MeV", "is_correct": false}, {"key": "D", "text": "200 MeV", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "2 MeV is far too small. This is roughly the energy of a single gamma ray photon, not the total fission energy.", "misconception": "Underestimating fission energy by two orders of magnitude"}, {"option_key": "B", "hint": "20 MeV is the typical energy released in a single alpha decay, not fission. Fission releases about 10 times more energy.", "misconception": "Confusing fission energy with alpha decay energy"}, {"option_key": "C", "hint": "2000 MeV is ten times the actual fission energy. The binding energy per nucleon difference accounts for about 200 MeV.", "misconception": "Overestimating fission energy by an order of magnitude"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The decay constant of a radioactive substance is 0.0231 per minute. Its half-life is approximately:", "explanation": "Using T₁/₂ = 0.693/λ = 0.693/0.0231 = 30 minutes. The half-life and decay constant are inversely related through the factor ln2 = 0.693.", "correct_answer": "C", "concept_tags": ["decay-constant", "half-life", "radioactive-decay-law"], "payload": {"question_id": "cuet-phy-nuclei-decay-09", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "10 minutes", "is_correct": false}, {"key": "B", "text": "20 minutes", "is_correct": false}, {"key": "C", "text": "30 minutes", "is_correct": true}, {"key": "D", "text": "45 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "T₁/₂ = 0.693/0.0231 = 30 min, not 10 min. Check your arithmetic: 0.693/0.0231 ≠ 10.", "misconception": "Arithmetic error in division"}, {"option_key": "B", "hint": "20 minutes would require λ = 0.693/20 = 0.0347 per min, which does not match the given λ = 0.0231.", "misconception": "Incorrect calculation of the half-life"}, {"option_key": "D", "hint": "45 minutes would require λ = 0.693/45 = 0.0154 per min. The given λ = 0.0231 corresponds to T₁/₂ = 30 min.", "misconception": "Using an incorrect formula or arithmetic error"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a nuclear reactor, the function of the moderator is to:", "explanation": "In a nuclear reactor, the moderator (commonly heavy water D₂O, graphite, or ordinary water) slows down fast neutrons produced during fission to thermal energies (~0.025 eV). Slow (thermal) neutrons have a much higher probability of causing fission in ²³⁵U compared to fast neutrons. The moderator achieves this through elastic collisions with neutrons.", "correct_answer": "B", "concept_tags": ["nuclear-reactor", "moderator", "thermal-neutrons", "chain-reaction"], "payload": {"question_id": "cuet-phy-nuclei-decay-10", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "Absorb excess neutrons to control the chain reaction", "is_correct": false}, {"key": "B", "text": "Slow down fast neutrons to thermal energies", "is_correct": true}, {"key": "C", "text": "Shield the reactor from radiation leakage", "is_correct": false}, {"key": "D", "text": "Increase the speed of neutrons for efficient fission", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Absorbing excess neutrons is the function of control rods (typically cadmium or boron), not the moderator.", "misconception": "Confusing the role of moderator with control rods"}, {"option_key": "C", "hint": "Radiation shielding is provided by the thick concrete and lead walls around the reactor, not by the moderator.", "misconception": "Confusing the role of moderator with radiation shielding"}, {"option_key": "D", "hint": "The moderator slows down neutrons, not speeds them up. Fast neutrons are less efficient at causing ²³⁵U fission.", "misconception": "Reversing the function of the moderator"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A radioactive nucleus ²³⁶X undergoes a series of alpha and beta-minus decays to finally become ²⁰⁸Y. The number of alpha and beta-minus particles emitted are, respectively:", "explanation": "Let the number of alpha decays = a and beta-minus decays = b. Each alpha decay reduces A by 4 and Z by 2. Each β⁻ decay increases Z by 1 with no change in A. Change in mass number: 236 − 208 = 28 = 4a, so a = 7. For atomic number: if Z_X is the initial atomic number and Z_Y is the final, then Z_X − 2a + b = Z_Y. However, since only A values are given, we use the mass number relation: a = 28/4 = 7. For β⁻ decays, we need Z values. Since this follows the thorium decay series (²³⁶₉₀Th → ²⁰⁸₈₂Pb pattern): Z change = 90 − 82 = 8 = 2a − b = 14 − b, so b = 6. The answer is 7 alpha and 6 beta-minus particles. (Note: In standard decay chains like ²³²Th series, the pattern of 7α and 4β⁻ is typical when Z_X − Z_Y = 2a − b = 10. Here with the given numbers, 7α and 4β⁻ gives Z change = 14 − 4 = 10.)", "correct_answer": "D", "concept_tags": ["alpha-decay", "beta-decay", "decay-series", "mass-number", "atomic-number"], "payload": {"question_id": "cuet-phy-nuclei-decay-11", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "analyze", "options": [{"key": "A", "text": "7 alpha and 6 beta-minus", "is_correct": false}, {"key": "B", "text": "6 alpha and 4 beta-minus", "is_correct": false}, {"key": "C", "text": "5 alpha and 8 beta-minus", "is_correct": false}, {"key": "D", "text": "7 alpha and 4 beta-minus", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "While 7 alpha decays is correct (28/4 = 7), the number of β⁻ decays depends on the Z values. In the standard thorium series, 4 β⁻ decays are emitted, not 6.", "misconception": "Incorrect calculation of the number of beta decays"}, {"option_key": "B", "hint": "6 alpha decays would reduce A by only 24 (to 212), not to 208. The mass number change requires exactly 7 alpha decays.", "misconception": "Incorrect calculation of the number of alpha decays"}, {"option_key": "C", "hint": "5 alpha decays would reduce A by only 20 (to 216), which does not match the final mass number of 208.", "misconception": "Incorrect calculation of mass number change in alpha decay"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The activity of a radioactive sample decreases from 6400 disintegrations per second to 100 disintegrations per second in 30 minutes. The half-life of the sample is:", "explanation": "Using A = A₀(1/2)ⁿ, where n is the number of half-lives: 100 = 6400 × (1/2)ⁿ, so (1/2)ⁿ = 100/6400 = 1/64 = (1/2)⁶. Therefore n = 6 half-lives in 30 minutes. Half-life T₁/₂ = 30/6 = 5 minutes.", "correct_answer": "A", "concept_tags": ["activity", "half-life", "exponential-decay", "numerical"], "payload": {"question_id": "cuet-phy-nuclei-decay-12", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "5 minutes", "is_correct": true}, {"key": "B", "text": "6 minutes", "is_correct": false}, {"key": "C", "text": "10 minutes", "is_correct": false}, {"key": "D", "text": "15 minutes", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "6 minutes would give n = 30/6 = 5 half-lives, reducing activity by a factor of 2⁵ = 32. But 6400/32 = 200, not 100.", "misconception": "Confusing the number of half-lives with the half-life value"}, {"option_key": "C", "hint": "10 minutes would give n = 30/10 = 3 half-lives, reducing activity by 2³ = 8. But 6400/8 = 800, not 100.", "misconception": "Incorrect division to find number of half-lives"}, {"option_key": "D", "hint": "15 minutes gives n = 2, so activity = 6400/4 = 1600, far from 100. The ratio 6400/100 = 64 = 2⁶ requires 6 half-lives.", "misconception": "Grossly underestimating the number of half-lives required"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): In nuclear fusion, two light nuclei combine to form a heavier nucleus with release of energy.\nReason (R): The binding energy per nucleon of the product nucleus is greater than that of the reacting light nuclei.", "explanation": "Both the assertion and reason are correct, and the reason correctly explains the assertion. In nuclear fusion, light nuclei (like hydrogen isotopes) combine to form a heavier nucleus (like helium). Energy is released because the binding energy per nucleon increases when moving from very light nuclei toward the iron region of the binding energy curve. The mass defect of the product is greater, meaning the product is more tightly bound, and the difference in binding energy is released as kinetic energy and radiation.", "correct_answer": "A", "concept_tags": ["nuclear-fusion", "binding-energy-per-nucleon", "energy-release", "light-nuclei"], "payload": {"question_id": "cuet-phy-nuclei-decay-13", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The higher binding energy per nucleon of the product is precisely the reason energy is released. The excess binding energy converts to kinetic energy, so R directly explains A.", "misconception": "Failing to see the direct causal link between binding energy increase and energy release"}, {"option_key": "C", "hint": "The reason is factually correct: on the binding energy curve, fusion products of light nuclei have higher BE/A than the reactants.", "misconception": "Incorrectly thinking binding energy per nucleon decreases in fusion"}, {"option_key": "D", "hint": "The assertion is correct: fusion of light nuclei (e.g., ²H + ³H → ⁴He + n) does release energy. This is the energy source of stars.", "misconception": "Thinking fusion absorbs energy rather than releases it"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The energy spectrum of electrons emitted in beta-minus decay is continuous, ranging from zero to a maximum value.\nReason (R): In beta-minus decay, the energy is shared between the electron and the antineutrino in varying proportions.", "explanation": "Both A and R are correct, and R is the correct explanation of A. In β⁻ decay, the available energy (Q-value minus the recoil energy of the daughter nucleus) is shared between the emitted electron and the antineutrino. Since this is a three-body decay (daughter nucleus, electron, antineutrino), the electron can carry any fraction of the available energy from nearly zero to the maximum (when the antineutrino gets negligible energy). This variable sharing produces the continuous energy spectrum. Pauli originally postulated the neutrino specifically to explain this continuous spectrum.", "correct_answer": "A", "concept_tags": ["beta-decay", "energy-spectrum", "antineutrino", "continuous-spectrum", "Pauli"], "payload": {"question_id": "cuet-phy-nuclei-decay-14", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The energy sharing between the electron and antineutrino is precisely the cause of the continuous spectrum. If only the electron were emitted, the spectrum would be discrete.", "misconception": "Not recognizing that variable energy sharing directly causes the continuous spectrum"}, {"option_key": "C", "hint": "The reason is correct. The three-body nature of β⁻ decay allows the electron-antineutrino energy partition to vary continuously.", "misconception": "Incorrectly thinking beta decay is a two-body process"}, {"option_key": "D", "hint": "The assertion is experimentally verified: beta particles have a continuous energy spectrum from 0 to E_max.", "misconception": "Thinking beta particles have a discrete energy spectrum like alpha particles"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following types of radiation (Column-I) with their properties (Column-II):\n\nColumn-I:\nA. Alpha rays\nB. Beta-minus rays\nC. Gamma rays\nD. Neutrino\n\nColumn-II:\n1. Uncharged, massless (or nearly massless), weakly interacting\n2. Helium nuclei with high ionizing power and low penetration\n3. Electromagnetic radiation with highest penetrating power\n4. Electrons with continuous energy spectrum", "explanation": "Alpha rays are helium nuclei (₂He⁴) with high ionizing power but low penetrating ability (A→2). Beta-minus rays are electrons emitted from the nucleus with a continuous energy spectrum due to energy sharing with the antineutrino (B→4). Gamma rays are electromagnetic radiation with the highest penetrating power among the three types of nuclear radiation (C→3). Neutrinos are uncharged, nearly massless particles that interact very weakly with matter (D→1).", "correct_answer": "B", "concept_tags": ["alpha-rays", "beta-rays", "gamma-rays", "neutrino", "properties"], "payload": {"question_id": "cuet-phy-nuclei-decay-15", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "A-2, B-3, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "D", "text": "A-1, B-2, C-4, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps beta rays and gamma rays. Beta rays are electrons (B→4), while gamma rays are electromagnetic radiation (C→3).", "misconception": "Confusing the nature of beta and gamma radiation"}, {"option_key": "C", "hint": "Alpha rays are helium nuclei (A→2), not electrons. This option incorrectly assigns electron properties to alpha particles.", "misconception": "Confusing alpha particles with electrons"}, {"option_key": "D", "hint": "Alpha rays are charged helium nuclei, not uncharged weakly interacting particles. The neutrino has property 1.", "misconception": "Confusing alpha particles with neutrinos"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following nuclear reactor components (Column-I) with their materials and functions (Column-II):\n\nColumn-I:\nA. Fuel\nB. Moderator\nC. Control rods\nD. Coolant\n\nColumn-II:\n1. Cadmium or boron rods — absorb excess neutrons\n2. Heavy water or liquid sodium — transfers heat to generate steam\n3. Enriched uranium (²³⁵U) or plutonium (²³⁹Pu) — undergoes fission\n4. Heavy water or graphite — slows down neutrons", "explanation": "The fuel in a nuclear reactor is enriched uranium or plutonium which undergoes fission (A→3). The moderator is heavy water or graphite which slows down fast neutrons to thermal energies (B→4). Control rods are made of cadmium or boron which have high neutron absorption cross-sections to regulate the chain reaction (C→1). The coolant is heavy water or liquid sodium which transfers the heat generated in the reactor core to produce steam for electricity generation (D→2).", "correct_answer": "C", "concept_tags": ["nuclear-reactor", "fuel", "moderator", "control-rods", "coolant"], "payload": {"question_id": "cuet-phy-nuclei-decay-16", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-1, C-4, D-2", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-1, D-2", "is_correct": true}, {"key": "D", "text": "A-3, B-2, C-1, D-4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps the moderator and control rods. The moderator slows neutrons (B→4), while control rods absorb neutrons (C→1).", "misconception": "Confusing the functions of moderator and control rods"}, {"option_key": "B", "hint": "This assigns fission to the moderator and neutron slowing to the fuel, which is completely reversed.", "misconception": "Confusing the roles of fuel and moderator in a reactor"}, {"option_key": "D", "hint": "This swaps the coolant and moderator. The coolant transfers heat (D→2), while the moderator slows neutrons (B→4). Both may use heavy water, but their functions differ.", "misconception": "Confusing coolant and moderator because both can use heavy water"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "In gamma decay, the mass number (A) and atomic number (Z) of the nucleus remain unchanged.", "explanation": "This statement is TRUE. Gamma decay involves the emission of a high-energy photon from an excited nuclear state. Since a photon has zero mass number and zero charge, neither the mass number A nor the atomic number Z of the nucleus changes during gamma emission. The nucleus simply transitions from an excited state to a lower energy state (isomeric transition).", "correct_answer": "A", "concept_tags": ["gamma-decay", "mass-number", "atomic-number", "isomeric-transition"], "payload": {"question_id": "cuet-phy-nuclei-decay-17", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Gamma photons carry zero mass number and zero charge. Unlike alpha or beta decay, gamma emission does not change A or Z.", "misconception": "Confusing gamma decay with alpha or beta decay where A and/or Z change"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Nuclear fission can be achieved easily by bombarding any heavy nucleus with slow neutrons.", "explanation": "This statement is FALSE. Not all heavy nuclei undergo fission with slow (thermal) neutrons. Only specific fissile nuclei such as ²³⁵U, ²³³U, and ²³⁹Pu can be fissioned by slow neutrons. Other heavy nuclei like ²³⁸U require fast neutrons (energy > 1 MeV) to undergo fission and are called fissionable (not fissile). The distinction between fissile and fissionable materials is crucial in nuclear reactor physics.", "correct_answer": "B", "concept_tags": ["nuclear-fission", "fissile-material", "slow-neutrons", "uranium-235"], "payload": {"question_id": "cuet-phy-nuclei-decay-18", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Only specific fissile nuclei (²³⁵U, ²³³U, ²³⁹Pu) undergo fission with slow neutrons. Many heavy nuclei like ²³⁸U do not fission with thermal neutrons.", "misconception": "Assuming all heavy nuclei are equally fissile with slow neutrons"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b09');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A radioactive sample has a decay constant λ = 0.1 per second. If the sample initially contains 10⁶ atoms, its initial activity (rate of disintegration) is _____ disintegrations per second.", "explanation": "Activity is defined as A = λN, where λ is the decay constant and N is the number of radioactive atoms. Initial activity A₀ = λN₀ = 0.1 × 10⁶ = 10⁵ = 1,00,000 disintegrations per second (or 10⁵ Bq). Activity represents the number of nuclear disintegrations occurring per unit time.", "correct_answer": "D", "concept_tags": ["activity", "decay-constant", "number-of-atoms", "disintegration-rate"], "payload": {"question_id": "cuet-phy-nuclei-decay-19", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "10⁷", "is_correct": false}, {"key": "B", "text": "10⁶", "is_correct": false}, {"key": "C", "text": "10⁴", "is_correct": false}, {"key": "D", "text": "10⁵", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10⁷ would mean A = 10 × N₀, but the decay constant is 0.1 (less than 1), so A must be less than N₀.", "misconception": "Multiplying instead of correctly applying A = λN"}, {"option_key": "B", "hint": "10⁶ equals N₀ itself. Activity A = λN₀ = 0.1 × 10⁶ = 10⁵, not 10⁶.", "misconception": "Confusing the number of atoms with the activity"}, {"option_key": "C", "hint": "10⁴ would require λ = 10⁴/10⁶ = 0.01, but the given λ is 0.1. Check: 0.1 × 10⁶ = 10⁵.", "misconception": "Arithmetic error in computing λN"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-decay", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A hospital uses a radioactive isotope ¹³¹I (iodine-131) with a half-life of 8 days for thyroid diagnosis. A fresh sample has an activity of 4.8 × 10⁸ Bq on the day it is delivered. The hospital plans to use it when the activity drops to 6 × 10⁷ Bq.\n\nAfter how many days from delivery can the hospital use the sample?", "explanation": "Using A = A₀(1/2)ⁿ, where n = t/T₁/₂. We need: 6 × 10⁷ = 4.8 × 10⁸ × (1/2)ⁿ. So (1/2)ⁿ = 6 × 10⁷ / 4.8 × 10⁸ = 1/8 = (1/2)³. Therefore n = 3 half-lives. Time t = 3 × 8 = 24 days. The hospital can use the sample 24 days after delivery when its activity has decreased to the required level.", "correct_answer": "C", "concept_tags": ["half-life", "activity", "iodine-131", "medical-application", "exponential-decay"], "payload": {"question_id": "cuet-phy-nuclei-decay-20", "subtopic": "Radioactive Decay", "topic_name": "Radioactive Decay", "bloom_level": "apply", "options": [{"key": "A", "text": "8 days", "is_correct": false}, {"key": "B", "text": "16 days", "is_correct": false}, {"key": "C", "text": "24 days", "is_correct": true}, {"key": "D", "text": "32 days", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "After 8 days (1 half-life), activity = 4.8 × 10⁸ / 2 = 2.4 × 10⁸ Bq, which is still much higher than the required 6 × 10⁷ Bq.", "misconception": "Assuming only one half-life is needed without checking the activity ratio"}, {"option_key": "B", "hint": "After 16 days (2 half-lives), activity = 4.8 × 10⁸ / 4 = 1.2 × 10⁸ Bq, still above the target of 6 × 10⁷ Bq.", "misconception": "Insufficient number of half-lives calculated"}, {"option_key": "D", "hint": "After 32 days (4 half-lives), activity = 4.8 × 10⁸ / 16 = 3 × 10⁷ Bq, which overshoots below the target. The ratio 4.8 × 10⁸ / 6 × 10⁷ = 8 = 2³ requires exactly 3 half-lives = 24 days.", "misconception": "Overcounting the number of half-lives required"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The value of 1 atomic mass unit (1 u) in terms of energy is approximately:", "explanation": "By Einstein''s mass-energy equivalence E = mc², 1 atomic mass unit (1 u = 1.66054 × 10⁻²⁷ kg) corresponds to an energy of 931.5 MeV. This conversion factor is fundamental in nuclear physics for calculating binding energies and mass defects.", "correct_answer": "C", "concept_tags": ["atomic-mass-unit", "mass-energy-equivalence", "MeV"], "payload": {"question_id": "cuet-phy-nuclei-properties-01", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "931.5 keV", "is_correct": false}, {"key": "B", "text": "931.5 GeV", "is_correct": false}, {"key": "C", "text": "931.5 MeV", "is_correct": true}, {"key": "D", "text": "9.315 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "931.5 keV is a thousand times smaller than the correct value. The correct unit is MeV (mega electron volt), not keV (kilo electron volt).", "misconception": "Confusing keV with MeV; 1 MeV = 1000 keV"}, {"option_key": "B", "hint": "931.5 GeV is a thousand times larger than the correct value. 1 GeV = 1000 MeV, so this would be 931,500 MeV.", "misconception": "Confusing GeV with MeV"}, {"option_key": "D", "hint": "9.315 MeV is off by a factor of 100. The standard value is 931.5 MeV per atomic mass unit.", "misconception": "Misplacing the decimal point in the conversion factor"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The nuclear radius R is related to the mass number A by the relation R = R₀A^(1/3). The value of R₀ is approximately:", "explanation": "Experimentally, the nuclear radius follows the empirical formula R = R₀A^(1/3), where R₀ ≈ 1.2 fm (1.2 × 10⁻¹⁵ m). This relation shows that nuclear volume is directly proportional to the mass number A, implying constant nuclear density.", "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "fermi"], "payload": {"question_id": "cuet-phy-nuclei-properties-02", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "1.2 × 10⁻¹⁰ m", "is_correct": false}, {"key": "B", "text": "1.2 × 10⁻¹⁵ m", "is_correct": true}, {"key": "C", "text": "1.2 × 10⁻²⁰ m", "is_correct": false}, {"key": "D", "text": "1.2 × 10⁻⁸ m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10⁻¹⁰ m (1 Å) is the order of atomic size, not nuclear size. Nuclei are about 100,000 times smaller than atoms.", "misconception": "Confusing atomic radius with nuclear radius"}, {"option_key": "C", "hint": "10⁻²⁰ m is far too small even for a nucleus. Nuclear sizes are of the order of femtometres (10⁻¹⁵ m).", "misconception": "Using an incorrect order of magnitude for nuclear dimensions"}, {"option_key": "D", "hint": "10⁻⁸ m is the order of atomic diameter, not nuclear radius. The nucleus is roughly 10⁵ times smaller than the atom.", "misconception": "Confusing atomic dimensions with nuclear dimensions"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Nuclei having the same mass number but different atomic numbers are called:", "explanation": "Isobars are nuclei that share the same mass number (A) but have different atomic numbers (Z). For example, ¹⁴C (Z = 6) and ¹⁴N (Z = 7) are isobars. Isotopes have the same Z but different A; isotones have the same neutron number (A − Z).", "correct_answer": "A", "concept_tags": ["isobars", "mass-number", "atomic-number", "nuclear-terminology"], "payload": {"question_id": "cuet-phy-nuclei-properties-03", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "Isobars", "is_correct": true}, {"key": "B", "text": "Isotopes", "is_correct": false}, {"key": "C", "text": "Isotones", "is_correct": false}, {"key": "D", "text": "Isomers", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Isotopes have the same atomic number (Z) but different mass numbers (A). The question states different atomic numbers, so these cannot be isotopes.", "misconception": "Confusing isotopes (same Z, different A) with isobars (same A, different Z)"}, {"option_key": "C", "hint": "Isotones have the same number of neutrons (N = A − Z) but different atomic numbers and mass numbers.", "misconception": "Confusing isotones (same N) with isobars (same A)"}, {"option_key": "D", "hint": "Isomers are nuclei with the same Z and A but in different energy states. They are not defined by having different atomic numbers.", "misconception": "Confusing nuclear isomers with isobars"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The density of nuclear matter is approximately:", "explanation": "Nuclear density is nearly constant for all nuclei and is approximately 2.3 × 10¹⁷ kg/m³. This follows from the relation R = R₀A^(1/3), which means volume V ∝ A. Since mass is also proportional to A (mass ≈ A × u), the density ρ = mass/volume is independent of A.", "correct_answer": "D", "concept_tags": ["nuclear-density", "nuclear-volume", "mass-number"], "payload": {"question_id": "cuet-phy-nuclei-properties-04", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "2.3 × 10³ kg/m³", "is_correct": false}, {"key": "B", "text": "2.3 × 10¹⁰ kg/m³", "is_correct": false}, {"key": "C", "text": "2.3 × 10²⁷ kg/m³", "is_correct": false}, {"key": "D", "text": "2.3 × 10¹⁷ kg/m³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10³ kg/m³ is the density of water. Nuclear matter is about 10¹⁴ times denser than water.", "misconception": "Confusing ordinary matter density with nuclear density"}, {"option_key": "B", "hint": "10¹⁰ kg/m³ is too low for nuclear matter. The incredibly small nuclear volume leads to a much higher density (~10¹⁷ kg/m³).", "misconception": "Underestimating nuclear density by several orders of magnitude"}, {"option_key": "C", "hint": "10²⁷ kg/m³ is ten orders of magnitude too high. The correct nuclear density is about 2.3 × 10¹⁷ kg/m³.", "misconception": "Overestimating nuclear density"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the nuclear radii of two nuclei with mass numbers 27 and 125 is:", "explanation": "Using R = R₀A^(1/3), the ratio R₁/R₂ = (A₁/A₂)^(1/3) = (27/125)^(1/3) = 3/5. Here, 27^(1/3) = 3 and 125^(1/3) = 5.", "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "ratio-calculation"], "payload": {"question_id": "cuet-phy-nuclei-properties-05", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "27 : 125", "is_correct": false}, {"key": "B", "text": "3 : 5", "is_correct": true}, {"key": "C", "text": "5 : 3", "is_correct": false}, {"key": "D", "text": "9 : 25", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The ratio of radii is not the same as the ratio of mass numbers. R ∝ A^(1/3), so the cube root must be taken.", "misconception": "Assuming nuclear radius is directly proportional to A instead of A^(1/3)"}, {"option_key": "C", "hint": "The ratio 5:3 is inverted. Since the first nucleus has the smaller mass number (27), it has the smaller radius, so the ratio is 3:5.", "misconception": "Reversing the order of the ratio"}, {"option_key": "D", "hint": "9:25 = (3:5)² corresponds to the ratio of surface areas, not radii. The radius ratio uses the cube root of A.", "misconception": "Using A^(2/3) instead of A^(1/3) for the radius relation"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mass defect of a helium nucleus ⁴He is 0.0304 u. The binding energy of the helium nucleus is approximately:", "explanation": "Binding energy = mass defect × 931.5 MeV/u = 0.0304 × 931.5 = 28.3 MeV. This is the energy required to completely separate all nucleons (2 protons and 2 neutrons) in the ⁴He nucleus.", "correct_answer": "C", "concept_tags": ["binding-energy", "mass-defect", "helium-nucleus", "numerical"], "payload": {"question_id": "cuet-phy-nuclei-properties-06", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "28.3 keV", "is_correct": false}, {"key": "B", "text": "7.07 MeV", "is_correct": false}, {"key": "C", "text": "28.3 MeV", "is_correct": true}, {"key": "D", "text": "283 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "28.3 keV uses the wrong unit. The conversion factor 931.5 already gives MeV, not keV. The correct answer is 28.3 MeV.", "misconception": "Confusing MeV with keV in the mass-energy conversion"}, {"option_key": "B", "hint": "7.07 MeV is the binding energy per nucleon (28.3/4), not the total binding energy of the nucleus.", "misconception": "Confusing total binding energy with binding energy per nucleon"}, {"option_key": "D", "hint": "283 MeV is ten times too large. Check: 0.0304 × 931.5 ≈ 28.3 MeV, not 283 MeV.", "misconception": "Arithmetic error — misplacing the decimal point"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The binding energy per nucleon is maximum for nuclei in the vicinity of:", "explanation": "The binding energy per nucleon (BE/A) curve shows a maximum of about 8.75 MeV/nucleon near iron (A ≈ 56). This makes iron-56 one of the most stable nuclei. Lighter nuclei gain stability through fusion, while heavier nuclei gain stability through fission, both moving toward this peak.", "correct_answer": "A", "concept_tags": ["binding-energy-per-nucleon", "nuclear-stability", "iron-56", "BE-curve"], "payload": {"question_id": "cuet-phy-nuclei-properties-07", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Iron (A ≈ 56)", "is_correct": true}, {"key": "B", "text": "Uranium (A ≈ 238)", "is_correct": false}, {"key": "C", "text": "Helium (A = 4)", "is_correct": false}, {"key": "D", "text": "Hydrogen (A = 1)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Uranium has a lower BE/A (~7.6 MeV) than iron. Heavy nuclei beyond iron have decreasing BE/A, which is why fission of heavy nuclei releases energy.", "misconception": "Assuming the heaviest nuclei are the most stable"}, {"option_key": "C", "hint": "⁴He has an unusually high BE/A (~7.07 MeV) for its mass number but it is still less than that of iron (~8.75 MeV). ⁴He is a local peak, not the global maximum.", "misconception": "Confusing the local stability peak of He-4 with the overall maximum"}, {"option_key": "D", "hint": "Hydrogen (¹H) has no binding energy at all since it consists of only one proton — there is nothing to bind.", "misconception": "Not understanding that a single nucleon has zero binding energy"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the nucleus of ²⁷Al has a nuclear radius of approximately 3.6 fm, the nuclear radius of ¹²⁵Te is approximately:", "explanation": "Using R = R₀A^(1/3), R(Te)/R(Al) = (125/27)^(1/3) = 5/3. Therefore, R(Te) = (5/3) × 3.6 = 6.0 fm. We use the fact that 125^(1/3) = 5 and 27^(1/3) = 3.", "correct_answer": "D", "concept_tags": ["nuclear-radius", "mass-number", "cube-root", "numerical"], "payload": {"question_id": "cuet-phy-nuclei-properties-08", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "apply", "options": [{"key": "A", "text": "16.7 fm", "is_correct": false}, {"key": "B", "text": "2.16 fm", "is_correct": false}, {"key": "C", "text": "10.0 fm", "is_correct": false}, {"key": "D", "text": "6.0 fm", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "16.7 fm results from using the ratio of mass numbers directly (3.6 × 125/27) instead of using the cube root relation R ∝ A^(1/3).", "misconception": "Assuming radius is directly proportional to mass number instead of A^(1/3)"}, {"option_key": "B", "hint": "2.16 fm is obtained by dividing instead of multiplying. Since Te has a larger A, its radius must be larger than Al''s radius of 3.6 fm.", "misconception": "Inverting the ratio — dividing by (5/3) instead of multiplying"}, {"option_key": "C", "hint": "10.0 fm is too large. The correct ratio is (125/27)^(1/3) = 5/3, giving 3.6 × 5/3 = 6.0 fm.", "misconception": "Using an incorrect cube root value"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is NOT a property of nuclear forces?", "explanation": "Nuclear forces are charge-independent — they act equally between p-p, n-n, and p-n pairs. They are short-range (effective only up to ~few femtometres), strongly attractive, and saturated (each nucleon interacts only with its nearest neighbours). They are NOT long-range forces like gravity or electrostatic forces.", "correct_answer": "B", "concept_tags": ["nuclear-forces", "short-range", "charge-independent", "saturation"], "payload": {"question_id": "cuet-phy-nuclei-properties-09", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "They are short-range forces", "is_correct": false}, {"key": "B", "text": "They obey the inverse square law", "is_correct": true}, {"key": "C", "text": "They are charge-independent", "is_correct": false}, {"key": "D", "text": "They show the property of saturation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear forces are indeed short-range, operating effectively within ~2–3 fm. This is a true property, so it cannot be the answer.", "misconception": null}, {"option_key": "C", "hint": "Nuclear forces are indeed charge-independent — the strong force between two protons equals that between two neutrons or a proton-neutron pair. This is a true property.", "misconception": null}, {"option_key": "D", "hint": "Saturation is a genuine property of nuclear forces meaning each nucleon interacts only with a limited number of neighbours. This explains why BE/A remains roughly constant.", "misconception": null}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The mass of a nucleus is always less than the sum of the masses of its constituent protons and neutrons. This difference in mass is called:", "explanation": "The mass defect (Δm) is the difference between the sum of masses of individual nucleons and the actual nuclear mass: Δm = [Zmₚ + (A − Z)mₙ] − M. This ''missing'' mass has been converted into binding energy (BE = Δm × c²) that holds the nucleus together.", "correct_answer": "C", "concept_tags": ["mass-defect", "binding-energy", "nucleons", "mass-energy-equivalence"], "payload": {"question_id": "cuet-phy-nuclei-properties-10", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "Packing fraction", "is_correct": false}, {"key": "B", "text": "Binding energy", "is_correct": false}, {"key": "C", "text": "Mass defect", "is_correct": true}, {"key": "D", "text": "Mass excess", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Packing fraction is defined as (exact atomic mass − mass number)/mass number. It is related to but not the same as mass defect.", "misconception": "Confusing packing fraction with mass defect"}, {"option_key": "B", "hint": "Binding energy is the energy equivalent of the mass defect (BE = Δm × 931.5 MeV), not the mass difference itself.", "misconception": "Confusing the mass difference with its energy equivalent"}, {"option_key": "D", "hint": "Mass excess is defined as (atomic mass − A) in atomic mass units. It is a different quantity from mass defect.", "misconception": "Confusing mass excess with mass defect"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The masses of a proton, neutron, and the ¹⁶O nucleus are 1.00728 u, 1.00866 u, and 15.99053 u respectively. The binding energy per nucleon of ¹⁶O is approximately:", "explanation": "For ¹⁶O: Z = 8, A = 16, N = 8. Sum of masses = 8(1.00728) + 8(1.00866) = 8.05824 + 8.06928 = 16.12752 u. Mass defect Δm = 16.12752 − 15.99053 = 0.13699 u. Binding energy = 0.13699 × 931.5 = 127.6 MeV. BE per nucleon = 127.6/16 ≈ 7.97 MeV/nucleon.", "correct_answer": "A", "concept_tags": ["binding-energy-per-nucleon", "mass-defect", "oxygen-16", "numerical-problem"], "payload": {"question_id": "cuet-phy-nuclei-properties-11", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "7.97 MeV/nucleon", "is_correct": true}, {"key": "B", "text": "127.6 MeV/nucleon", "is_correct": false}, {"key": "C", "text": "0.137 MeV/nucleon", "is_correct": false}, {"key": "D", "text": "5.24 MeV/nucleon", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "127.6 MeV is the total binding energy of ¹⁶O, not the binding energy per nucleon. You must divide by A = 16 to get BE per nucleon.", "misconception": "Forgetting to divide total binding energy by the mass number"}, {"option_key": "C", "hint": "0.137 MeV/nucleon comes from dividing the mass defect in u by A without converting to MeV. You must multiply Δm by 931.5 MeV/u first.", "misconception": "Forgetting to convert mass defect from atomic mass units to MeV"}, {"option_key": "D", "hint": "5.24 MeV/nucleon does not match any correct calculation path. Recheck: Δm = 0.137 u → BE = 127.6 MeV → BE/A = 7.97 MeV.", "misconception": "Arithmetic error in computing sum of nucleon masses or mass defect"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A nucleus has a radius of 3.6 fm. If the nuclear density is approximately 2.3 × 10¹⁷ kg/m³, the approximate mass number of this nucleus is:", "explanation": "Using R = R₀A^(1/3), A = (R/R₀)³ = (3.6/1.2)³ = (3)³ = 27. Alternatively, from density: mass = ρ × (4/3)πR³ and mass ≈ A × 1.66 × 10⁻²⁷ kg. Either way, A = 27, which corresponds to aluminium (²⁷Al).", "correct_answer": "B", "concept_tags": ["nuclear-radius", "mass-number", "nuclear-density", "numerical-problem"], "payload": {"question_id": "cuet-phy-nuclei-properties-12", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "8", "is_correct": false}, {"key": "B", "text": "27", "is_correct": true}, {"key": "C", "text": "64", "is_correct": false}, {"key": "D", "text": "125", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A = 8 gives R = 1.2 × 8^(1/3) = 1.2 × 2 = 2.4 fm, not 3.6 fm.", "misconception": "Incorrectly computing (R/R₀)³"}, {"option_key": "C", "hint": "A = 64 gives R = 1.2 × 64^(1/3) = 1.2 × 4 = 4.8 fm, which is larger than 3.6 fm.", "misconception": "Using R/R₀ = 4 instead of the correct value 3"}, {"option_key": "D", "hint": "A = 125 gives R = 1.2 × 125^(1/3) = 1.2 × 5 = 6.0 fm, much larger than 3.6 fm.", "misconception": "Using R/R₀ = 5 instead of the correct value 3"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The density of nuclear matter is independent of the mass number A.\nReason (R): The nuclear radius is proportional to the cube root of the mass number, i.e., R = R₀A^(1/3).", "explanation": "Both A and R are correct, and R is the correct explanation of A. Since R ∝ A^(1/3), the nuclear volume V = (4/3)πR³ ∝ A. The nuclear mass is also proportional to A (mass ≈ A × u). Therefore, density ρ = mass/volume ∝ A/A = constant, independent of A. The R = R₀A^(1/3) relation directly leads to constant density.", "correct_answer": "A", "concept_tags": ["nuclear-density", "nuclear-radius", "mass-number", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-nuclei-properties-13", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: the R ∝ A^(1/3) relation makes V ∝ A, and since mass ∝ A, density becomes independent of A. The reason is the correct explanation.", "misconception": "Failing to see the logical connection between R ∝ A^(1/3) and constant nuclear density"}, {"option_key": "C", "hint": "The reason R = R₀A^(1/3) is experimentally verified and is a well-established empirical formula. It is definitely correct.", "misconception": "Doubting the validity of the nuclear radius formula"}, {"option_key": "D", "hint": "The assertion is correct — nuclear density (~2.3 × 10¹⁷ kg/m³) is indeed the same for all nuclei regardless of mass number.", "misconception": "Incorrectly believing nuclear density varies with mass number"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The binding energy per nucleon for ⁵⁶Fe is higher than that for ²³⁸U.\nReason (R): Nuclear forces obey the inverse square law similar to gravitational and electrostatic forces.", "explanation": "The assertion is correct — ⁵⁶Fe has the highest BE/A (~8.75 MeV) while ²³⁸U has a lower value (~7.6 MeV). However, the reason is incorrect — nuclear forces do NOT obey the inverse square law. Nuclear forces are short-range (effective only within ~2–3 fm) and do not follow any simple power law like 1/r².", "correct_answer": "C", "concept_tags": ["binding-energy-per-nucleon", "nuclear-forces", "iron-56", "uranium-238", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-nuclei-properties-14", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Even if both statements were correct, the inverse square law for nuclear forces would not explain why iron has the highest BE/A. But more importantly, the reason itself is factually wrong.", "misconception": "Incorrectly believing nuclear forces follow the inverse square law"}, {"option_key": "B", "hint": "The reason statement is factually incorrect — nuclear forces are short-range and do NOT obey the inverse square law. So option B cannot apply.", "misconception": "Accepting the inverse square law claim for nuclear forces as true"}, {"option_key": "D", "hint": "The assertion is correct — ⁵⁶Fe does have a higher BE/A than ²³⁸U. This is a well-known fact from the BE/A curve.", "misconception": "Not knowing the relative positions of Fe and U on the BE/A curve"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Isotopes\n(Q) Isobars\n(R) Isotones\n(S) Isomers\n\nColumn II:\n(1) Same mass number, different atomic number\n(2) Same atomic number, different mass number\n(3) Same neutron number, different atomic number\n(4) Same Z and A, different nuclear energy states", "explanation": "Isotopes have the same atomic number Z but different mass number A (P→2). Isobars have the same mass number A but different atomic number Z (Q→1). Isotones have the same neutron number N but different Z (R→3). Isomers have the same Z and A but exist in different excited nuclear energy states (S→4).", "correct_answer": "D", "concept_tags": ["isotopes", "isobars", "isotones", "isomers", "nuclear-terminology", "match-the-following"], "payload": {"question_id": "cuet-phy-nuclei-properties-15", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "D", "text": "P→2, Q→1, R→3, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→1 means isotopes have the same mass number — this is wrong. Isotopes have the same atomic number (Z), not the same mass number. P should match with 2.", "misconception": "Confusing the definition of isotopes with isobars"}, {"option_key": "B", "hint": "R→4 implies isotones have different energy states — this is wrong. Isotones share the same neutron number. R should match with 3.", "misconception": "Confusing isotones with isomers"}, {"option_key": "C", "hint": "P→3 means isotopes have the same neutron number — this is wrong. Isotopes have the same atomic number (Z). P should match with 2.", "misconception": "Confusing isotopes with isotones"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Binding energy per nucleon of ²H\n(Q) Binding energy per nucleon of ⁴He\n(R) Binding energy per nucleon of ⁵⁶Fe\n(S) Binding energy per nucleon of ²³⁸U\n\nColumn II:\n(1) ~1.1 MeV\n(2) ~7.6 MeV\n(3) ~8.75 MeV\n(4) ~7.07 MeV", "explanation": "²H (deuteron) has BE/A ≈ 1.1 MeV (P→1), being the simplest bound nucleus. ⁴He has BE/A ≈ 7.07 MeV (Q→4), showing exceptional stability. ⁵⁶Fe has the highest BE/A ≈ 8.75 MeV (R→3), making it the most stable nucleus. ²³⁸U has BE/A ≈ 7.6 MeV (S→2), lower than iron due to greater Coulomb repulsion.", "correct_answer": "B", "concept_tags": ["binding-energy-per-nucleon", "BE-curve", "deuterium", "helium", "iron", "uranium", "match-the-following"], "payload": {"question_id": "cuet-phy-nuclei-properties-16", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→1, Q→4, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→1, Q→4, R→3, S→2", "is_correct": true}, {"key": "C", "text": "P→4, Q→1, R→3, S→2", "is_correct": false}, {"key": "D", "text": "P→1, Q→3, R→4, S→2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R→2 assigns 7.6 MeV to ⁵⁶Fe, but iron has the maximum BE/A (~8.75 MeV) on the curve. R should match with 3.", "misconception": "Not knowing that iron has the highest binding energy per nucleon"}, {"option_key": "C", "hint": "P→4 assigns ~7.07 MeV to deuterium, but ²H is the weakest bound nucleus with BE/A ≈ 1.1 MeV. P should match with 1.", "misconception": "Confusing deuterium''s BE/A with that of helium-4"}, {"option_key": "D", "hint": "Q→3 assigns ~8.75 MeV to ⁴He, but helium has BE/A ≈ 7.07 MeV. The maximum ~8.75 MeV belongs to ⁵⁶Fe.", "misconception": "Assigning the maximum BE/A to helium instead of iron"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The nuclear force between two nucleons is independent of their electric charge.", "explanation": "This statement is TRUE. Nuclear forces are charge-independent, meaning the strong nuclear force between two protons, two neutrons, or a proton-neutron pair is essentially the same. This is a fundamental property of the strong nuclear interaction, confirmed by scattering experiments.", "correct_answer": "A", "concept_tags": ["nuclear-forces", "charge-independence", "true-false"], "payload": {"question_id": "cuet-phy-nuclei-properties-17", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Nuclear (strong) forces are indeed charge-independent. The nuclear force between p-p, n-n, and p-n pairs is the same. Do not confuse the nuclear force with the Coulomb force, which is charge-dependent.", "misconception": "Confusing nuclear force with electromagnetic force between protons"}]}}, {"chapter_id": "cuet-phy-atoms-nuclei", "topic_id": "cuet-phy-nuclei-properties", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "The nuclear density increases with increasing mass number A.", "explanation": "This statement is FALSE. Nuclear density is approximately constant (~2.3 × 10¹⁷ kg/m³) for all nuclei, regardless of mass number. Since R = R₀A^(1/3), the volume V = (4/3)πR³ ∝ A, and mass ∝ A, so density ρ = mass/volume remains constant and is independent of A.", "correct_answer": "B", "concept_tags": ["nuclear-density", "mass-number", "constant-density", "true-false"], "payload": {"question_id": "cuet-phy-nuclei-properties-18", "subtopic": "Nuclear Properties and Binding Energy", "topic_name": "Nuclear Properties and Binding Energy", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear density does NOT increase with A. Since volume ∝ A and mass ∝ A, the density remains constant. This is a direct consequence of R ∝ A^(1/3).", "misconception": "Assuming heavier nuclei are denser, similar to how denser elements exist in everyday life"}]}}]'::jsonb, 'deploy-2026-03-05-b09');

